const FW25_MAP = {202601:202501,202602:202502,202603:202503,202604:202504,202605:202505,202606:202506,202607:202507,202608:202508,202609:202509,202610:202510,202611:202511,202612:202512,202613:202513,202614:202514,202615:202515,202616:202516,202617:202517,202618:202518,202619:202519,202620:202520};

const fmt$ = n => n==null?"—":"$"+Math.abs(n).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2});
const fmtD = n => n==null?"—":(n>=0?"+":"-")+"$"+Math.abs(n).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2});
const fmtP = n => n==null?"—":(n>=0?"+":"")+n.toFixed(1)+"%";
const fmtST = n => n==null?"—":n.toFixed(1)+"%";
const fmtU = n => n==null?"—":Math.round(n).toLocaleString("en-US");
const clr = n => n==null?"#2d3752":n>=0?"#4ade80":"#f87171";
const stClr = n => n==null?"#2d3752":n>=80?"#4ade80":n>=60?"#f5a623":"#f87171";

function MultiSelect({label, options, selected, onChange, fmtOpt}) {
  const [open, setOpen] = useState(false);
  const all = selected.length===options.length;
  const toggle = v => selected.includes(v)?onChange(selected.filter(x=>x!==v)):onChange([...selected,v]);
  return (
    <div style={{position:"relative",display:"inline-block",minWidth:155}}>
      <button onClick={()=>setOpen(!open)} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#0a0f1e",padding:"7px 12px",borderRadius:6,cursor:"pointer",fontSize:14,width:"100%",textAlign:"left",display:"flex",justifyContent:"space-between",alignItems:"center",fontFamily:"'DM Sans',sans-serif"}}>
        <span>{label}: {all?"All":selected.length===0?"None":selected.length+" sel."}</span>
        <span style={{marginLeft:8,opacity:0.5}}>{open?"▲":"▼"}</span>
      </button>
      {open&&(
        <div style={{position:"absolute",zIndex:9999,top:"105%",left:0,background:"#ede9e3",border:"1px solid #d8d3c9",borderRadius:7,minWidth:210,maxHeight:280,overflowY:"auto",boxShadow:"0 12px 40px #0008"}}>
          <div onClick={()=>all?onChange([]):onChange([...options])} style={{padding:"8px 14px",cursor:"pointer",borderBottom:"1px solid #d8d3c9",color:"#0a0f1e",fontSize:14,fontWeight:600,fontFamily:"'DM Sans',sans-serif"}}>{all?"Deselect All":"Select All"}</div>
          {options.map(o=>(
            <div key={o} onClick={()=>toggle(o)} style={{padding:"6px 14px",cursor:"pointer",fontSize:14,color:selected.includes(o)?"#0a0f1e":"#0a0f1e",background:selected.includes(o)?"#e4ddd4":"transparent",display:"flex",alignItems:"center",gap:8,fontFamily:"'DM Sans',sans-serif"}}>
              <span style={{width:11,height:11,borderRadius:3,border:"1px solid #c4beb5",background:selected.includes(o)?"#c8934a":"transparent",display:"inline-block",flexShrink:0}}/>
              {fmtOpt?fmtOpt(o):o}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function KPI({label,value,delta,pct,stVal}) {
  const c = stVal!=null ? stClr(stVal) : (delta==null?"#2d3752":delta>=0?"#4ade80":"#f87171");
  return (
    <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,padding:"16px 18px",flex:1,minWidth:130}}>
      <div style={{fontSize:12,color:"#2d3752",fontFamily:"'DM Sans',sans-serif",letterSpacing:0.5,textTransform:"uppercase",marginBottom:6}}>{label}</div>
      <div style={{fontSize:22,fontWeight:700,color: stVal!=null?c:"#0a0f1e",fontFamily:"'DM Sans',sans-serif"}}>{value}</div>
      {delta!=null&&<div style={{marginTop:5,display:"flex",gap:7,alignItems:"center"}}>
        <span style={{fontSize:15,color:c,fontFamily:"'DM Sans',sans-serif"}}>{fmtD(delta)}</span>
        <span style={{fontSize:13,color:c,background:c+"22",borderRadius:4,padding:"2px 6px",fontFamily:"'DM Sans',sans-serif"}}>{fmtP(pct)}</span>
      </div>}
    </div>
  );
}

function STBar({val}) {
  if(val==null) return <span style={{color:"#3a5a7a",fontFamily:"'DM Sans',sans-serif",fontSize:14}}>—</span>;
  const capped = Math.min(val,100);
  const c = stClr(val);
  return (
    <div style={{display:"flex",alignItems:"center",gap:6,justifyContent:"flex-end"}}>
      <div style={{width:48,height:6,background:"#ede9e3",borderRadius:3,overflow:"hidden"}}>
        <div style={{width:capped+"%",height:"100%",background:c,borderRadius:3}}/>
      </div>
      <span style={{color:c,fontFamily:"'DM Sans',sans-serif",fontSize:14,minWidth:42,textAlign:"right"}}>{fmtST(val)}</span>
    </div>
  );
}


function Sparkline({prod}) {
  const vals = SPARK_DATA[prod] || [];
  if(!vals.length) return <span style={{color:"#2d3752",fontSize:13}}>—</span>;
  const max = Math.max(...vals, 1);
  const w = 6, gap = 2, h = 28;
  const total = vals.length*(w+gap)-gap;
  return (
    <svg width={total} height={h} style={{display:"block"}}>
      {vals.map((v,i)=>{
        const barH = Math.max(2, Math.round((v/max)*h));
        const c = v===Math.max(...vals)?"#4ade80":v===Math.min(...vals)?"#f87171":"#c8934a";
        return <rect key={i} x={i*(w+gap)} y={h-barH} width={w} height={barH} fill={c} rx={1}/>;
      })}
    </svg>
  );
}


function TopBottom3({rows, nameKey, valueKey, label, fmt: fmtFn}) {
  if(!rows||rows.length<2) return null;
  const sorted = [...rows].sort((a,b)=>(b[valueKey]||0)-(a[valueKey]||0));
  const top3 = sorted.slice(0,3);
  const bot3 = sorted.slice(-3).reverse();
  return (
    <div style={{display:"flex",gap:12,marginBottom:20,flexWrap:"wrap"}}>
      <div style={{background:"#f0faf5",border:"1px solid #b8deca",borderRadius:8,padding:"12px 16px",flex:1,minWidth:260}}>
        <div style={{fontSize:12,color:"#4ade80",letterSpacing:0.5,textTransform:"uppercase",marginBottom:8}}>Top 3 · {label}</div>
        {top3.map((r,i)=>(
          <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
            <span style={{fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{r[nameKey]}</span>
            <span style={{fontSize:14,color:"#4ade80",fontFamily:"DM Sans,sans-serif",fontWeight:600}}>{fmtFn(r[valueKey])}</span>
          </div>
        ))}
      </div>
      <div style={{background:"#fdf3f2",border:"1px solid #f0c0bb",borderRadius:8,padding:"12px 16px",flex:1,minWidth:260}}>
        <div style={{fontSize:12,color:"#f87171",letterSpacing:0.5,textTransform:"uppercase",marginBottom:8}}>Bottom 3 · {label}</div>
        {bot3.map((r,i)=>(
          <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
            <span style={{fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{r[nameKey]}</span>
            <span style={{fontSize:14,color:"#f87171",fontFamily:"DM Sans,sans-serif",fontWeight:600}}>{fmtFn(r[valueKey])}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function THead({cols,sort,onSort}) {
  return (
    <thead>
      <tr style={{background:"#ede9e3"}}>
        {cols.map(c=>(
          <th key={c.key} onClick={()=>onSort&&onSort(c.key)} style={{padding:"10px 14px",textAlign:c.num?"right":"left",fontSize:12,color:sort===c.key?"#c8934a":"#2d3752",fontFamily:"'DM Sans',sans-serif",letterSpacing:0.3,textTransform:"uppercase",cursor:onSort?"pointer":"default",background:sort===c.key?"#e4ddd4":"transparent",borderBottom:"1px solid #d8d3c9",whiteSpace:"nowrap"}}>
            {c.label}{sort===c.key?" ▼":""}
          </th>
        ))}
      </tr>
    </thead>
  );
}

const ALLOC_CATEGORIES = [
  {key:"5inch",    label:"5\" Orchids",   cycle:"weekly",  maxCases:2, packSize:10,
   prods:["PLANT-5-ORCHID","PLANT-ORCHID","ORCHID-PREMIUM-CERAMIC","ORCHID-PLANT","ORCHID-COLOR-EVERYDAY-5 IN","ORCHID-LARGE WHITE"]},
  {key:"3inch",    label:"3\" Orchids",   cycle:"monthly", maxCases:1, packSize:15,
   prods:["PLANT-ORCHID-SMALL","ORCHID-SMALL","ORCHID-TEACUP-3\""]},
  {key:"fused",    label:"5\" Fused",     cycle:"monthly", maxCases:1, packSize:10,
   prods:["PLANT-ORCHID-FUSED","ORCHID-FUSED-COLORED","ORCHID-CASCADE-FUSED"]},
  {key:"cascades", label:"Cascades",      cycle:"monthly", maxCases:1, packSize:null,
   prods:["PLANT-ORCHID-CASCADE-PREMIUM","ORCHID-WATERFALL-PREMIUM-5IN","ORCHID-CASCADE","PLANT-ORCHID-PREMIUM CASCADE"],
   packByVendor:{"BORING DECO":6,"GREEN CIRCLE":10}},
];

export default function App() {
  // ── PASSWORD GATE ─────────────────────────────────────────────────────────
  const CORRECT_PASSWORD = "Sprouts2026!";
  const [authenticated, setAuthenticated] = useState(false);
  const [pwInput, setPwInput] = useState("");
  const [pwError, setPwError] = useState(false);
  const [pwShake, setPwShake] = useState(false);

  const [tab, setTab] = useState("wow");
  const ALL_FWS_FULL = [202601,202602,202603,202604,202605,202606,202607,202608,202609,202610,202611,202612,202613,202614,202615,202616,202617,202618,202619,202620];
  const computePresetFWs = (preset) => {
    const sorted = [...ALL_FWS_FULL];
    if(preset==="last4") return sorted.slice(-4);
    if(preset==="last8") return sorted.slice(-8);
    return sorted;
  };
  const [selFW, setSelFW] = useState(ALL_FWS_FULL);
  const applyPreset = (preset) => { setDatePreset(preset); if(preset!=="custom") setSelFW(computePresetFWs(preset)); };
  const applyCustom = (from, to) => {
    const fws = ALL_FWS_FULL.filter(fw=>fw>=from&&fw<=to);
    setSelFW(fws.length>0?fws:[from]);
  };
  const [selDC, setSelDC] = useState([...ALL_DCS]);
  const [selProd, setSelProd] = useState(ALL_PRODUCTS.filter(p=>!['LAVENDER-BUNCH-DRIED','LAVENDER-SACHET'].includes(p)));
  const [selVendor, setSelVendor] = useState(ALL_VENDORS.filter(v=>!['CYMA','LAVENDER'].includes(v)));
  const [sortWow, setSortWow] = useState("sales");
  const [sortYTDProd, setSortYTDProd] = useState("s26");
  const [sortYTDDC, setSortYTDDC] = useState("s26");
  const [expandedDC, setExpandedDC] = useState(null);
  const [selCategory, setSelCategory] = useState(ALL_CATEGORIES.filter(c=>!['Lavender'].includes(c)));
  const [datePreset, setDatePreset] = useState("ytd");
  const [customFrom, setCustomFrom] = useState(ALL_FWS_FULL[0]);
  const [customTo, setCustomTo] = useState(ALL_FWS_FULL[ALL_FWS_FULL.length-1]);
  const [trendMetric, setTrendMetric] = useState("sales");
  const [trendView, setTrendView] = useState("yoy");
  const [storeSearch, setStoreSearch] = useState("");
  const [storeSortKey, setStoreSortKey] = useState("sales");
  const [storeWkFilter, setStoreWkFilter] = useState([...ALL_FWS_FULL]);
  const [storeDCFilter, setStoreDCFilter] = useState([...ALL_DCS]);
  const [allocBaseline, setAllocBaseline] = useState("last4");
  const [allocCustomFrom, setAllocCustomFrom] = useState(ALL_FWS_FULL[0]);
  const [allocCustomTo, setAllocCustomTo] = useState(ALL_FWS_FULL[ALL_FWS_FULL.length-1]);
  const [allocCategory, setAllocCategory] = useState(["5inch"]);
  const [allocDC, setAllocDC] = useState([...ALL_DCS]);
  const [allocSearch, setAllocSearch] = useState("");
  const [districtSort, setDistrictSort] = useState("s26");
  const [expandedDistrict, setExpandedDistrict] = useState(null);
  const [expandedStore, setExpandedStore] = useState(null);
  const [insightsOpen, setInsightsOpen] = useState(false);
  const [insightsTab, setInsightsTab] = useState("chat");
  const [chatMessages, setChatMessages] = useState([]);
  const [chatInput, setChatInput] = useState("");
  const [chatLoading, setChatLoading] = useState(false);
  // Export date — default to next Tuesday from today
  const [exportDate, setExportDate] = useState(()=>{
    const today = new Date();
    const day = today.getDay();
    const daysToTue = (2 - day + 7) % 7 || 7;
    const tue = new Date(today); tue.setDate(today.getDate() + daysToTue);
    return String(tue.getFullYear()) + String(tue.getMonth()+1).padStart(2,'0') + String(tue.getDate()).padStart(2,'0');
  });

  const selFWSorted = [...selFW].sort();
  const latestFW = selFWSorted[selFWSorted.length-1];
  const prevFW = selFWSorted[selFWSorted.length-2];
  const lyFW = latestFW ? FW25_MAP[latestFW] : null;

  const activeProdList = useMemo(()=>{
    if(selCategory.length===ALL_CATEGORIES.length) return selProd;
    const catProds = ALL_PRODUCTS.filter(p=>selCategory.includes(CATEGORY_MAP[p]));
    return selProd.filter(p=>catProds.includes(p));
  },[selCategory,selProd]);

  const filter26 = fw => DATA26.filter(d=>
    (!fw||d[0]===fw) && selDC.includes(d[1]) && activeProdList.includes(d[2]) && selVendor.includes(d[3])
  );
  const filter25 = fw => DATA25.filter(d=>
    (!fw||d[0]===fw) && selDC.includes(d[1]) && activeProdList.includes(d[2])
  );
  const filterAll26 = () => DATA26.filter(d=>
    selFW.includes(d[0]) && selDC.includes(d[1]) && activeProdList.includes(d[2]) && selVendor.includes(d[3])
  );

  const sumS = rows => rows.reduce((a,d)=>a+d[4],0);
  const sumU = rows => rows.reduce((a,d)=>a+d[5],0);
  const sumS25 = rows => rows.reduce((a,d)=>a+d[3],0);
  const sumU25 = rows => rows.reduce((a,d)=>a+d[4],0);
  const sumO25 = rows => rows.reduce((a,d)=>a+d[5],0);
  const calcST = (u,o) => o>0 ? u/o*100 : null;

  // Pack sizes per product (DATA26 d[6] is in cases; multiply to get pieces)
  const PROD_PACK = {"PLANT-5-ORCHID":10,"PLANT-ORCHID":10,"ORCHID-PREMIUM-CERAMIC":10,"ORCHID-PLANT":10,"ORCHID-COLOR-EVERYDAY-5 IN":10,"ORCHID-LARGE WHITE":10,"PLANT-ORCHID-SMALL":15,"ORCHID-SMALL":15,"ORCHID-TEACUP-3\"":15,"PLANT-ORCHID-FUSED":10,"ORCHID-CASCADE-FUSED":10,"ORCHID-FUSED-COLORED":10,"PLANT-ORCHID-CASCADE-PREMIUM":6,"ORCHID-WATERFALL-PREMIUM-5IN":6,"PLANT-ORCHID-PREMIUM CASCADE":6,"ORCHID-CASCADE":6,"ORCHID-ARRANGEMENT DUO":8,"ORCHID-WATERFALL-PREMIUM-5IN":6,"ORCHID-MINI STADIUM-2.5IN":12,"ORCHID-PETITE GARDEN- 5IN":10,"ORCHID-SWEETHEART":10};

  // Compute outbound PIECES from DATA26 rows: cases * pack size per product.
  // Only counts rows where d[6] (cases) > 0 (delivery weeks only).
  const dmOutbound = (rows, fw) => {
    if (!rows || !rows.length) return 0;
    var total = 0;
    for (var i = 0; i < rows.length; i++) {
      var cases = rows[i][6];
      if (!cases || cases <= 0) continue;
      var pack = PROD_PACK[rows[i][2]] || 10;
      total += cases * pack;
    }
    return total;
  };

  const thisW = useMemo(()=>filter26(latestFW),[latestFW,selDC,selProd,selVendor,selCategory]);
  const lastW = useMemo(()=>prevFW?filter26(prevFW):[],[prevFW,selDC,selProd,selVendor,selCategory]);
  const lyW = useMemo(()=>lyFW?filter25(lyFW):[],[lyFW,selDC,selProd,selVendor,selCategory]);

  const thisS = sumS(thisW), thisU = sumU(thisW);
  const lastS = prevFW?sumS(lastW):null;
  const lyS = lyFW?sumS25(lyW):null;
  const thisST = null; // DATA26 outbound too sparse for reliable ST%
  const lastST = null; // DATA26 outbound too sparse
  const lyST = null; // FY25 outbound too sparse

  const wowD = lastS!=null?thisS-lastS:null, wowP = lastS?wowD/lastS*100:null;
  const yoyD = lyS!=null?thisS-lyS:null, yoyP = lyS?yoyD/lyS*100:null;
  const stDelta = null; // DATA26 outbound too sparse

  // By Product WoW
  const prodTable = useMemo(()=>{
    const m={}, p={}, l={};
    thisW.forEach(d=>{
      m[d[2]] = m[d[2]]||{s:0,u:0};
      m[d[2]].s+=d[4]; m[d[2]].u+=d[5];
    });
    lastW.forEach(d=>{p[d[2]]=(p[d[2]]||{s:0,u:0}); p[d[2]].s+=d[4]; p[d[2]].u+=d[5];});
    lyW.forEach(d=>{l[d[2]]=(l[d[2]]||{s:0,u:0,o:0}); l[d[2]].s+=d[3]; l[d[2]].u+=d[4]; l[d[2]].o+=d[5];});
    return Object.entries(m).map(([prod,cur])=>{
      const prv=p[prod]||{s:0,u:0}, ly=l[prod]||{s:0,u:0,o:0};
      const wd=prv.s>0?cur.s-prv.s:null, wp=prv.s>0?wd/prv.s*100:null;
      const yd=ly.s>0?cur.s-ly.s:null, yp=ly.s>0?yd/ly.s*100:null;
      // ST% for product row: filter thisW/lastW to that product, use DM outbound
      const prodRowsThis = thisW.filter(function(d){ return d[2]===prod; });
      const prodRowsLast = lastW.filter(function(d){ return d[2]===prod; });
      const st=null; // DATA26 outbound too sparse
      const stLy=null; const stDiff=null;
      const aur = cur.u>0?cur.s/cur.u:null;
      return {prod,sales:cur.s,units:cur.u,aur,wd,wp,lyS:ly.s||null,lyU:ly.u||0,yd,yp,st,stLy,stDiff};
    }).sort((a,b)=>
      sortWow==="sales"?b.sales-a.sales:
      sortWow==="wd"?(b.wd||0)-(a.wd||0):
      sortWow==="wp"?(b.wp||0)-(a.wp||0):
      sortWow==="st"?(b.st||0)-(a.st||0):
      sortWow==="yd"?(b.yd||0)-(a.yd||0):
      sortWow==="yp"?(b.yp||0)-(a.yp||0):
      b.sales-a.sales
    );
  },[thisW,lastW,lyW,sortWow,selCategory]);

  // By DC WoW
  const dcTable = useMemo(()=>{
    const m={}, p={}, l={};
    thisW.forEach(d=>{m[d[1]]=(m[d[1]]||{s:0,u:0}); m[d[1]].s+=d[4]; m[d[1]].u+=d[5];});
    lastW.forEach(d=>{p[d[1]]=(p[d[1]]||{s:0,u:0}); p[d[1]].s+=d[4]; p[d[1]].u+=d[5];});
    lyW.forEach(d=>{l[d[1]]=(l[d[1]]||{s:0,u:0,o:0}); l[d[1]].s+=d[3]; l[d[1]].u+=d[4]; l[d[1]].o+=d[5];});
    return Object.entries(m).map(([dc,cur])=>{
      const prv=p[dc]||{s:0,u:0}, ly=l[dc]||{s:0,u:0,o:0};
      const wd=prv.s>0?cur.s-prv.s:null, wp=prv.s>0?wd/prv.s*100:null;
      const yd=ly.s>0?cur.s-ly.s:null, yp=ly.s>0?yd/ly.s*100:null;
      // ST% per DC: filter thisW to that DC, use DM outbound
      const dcRowsThis = thisW.filter(function(d){ return d[1]===dc; });
      const dcRowsLast = lastW.filter(function(d){ return d[1]===dc; });
      const st=null; // DATA26 outbound too sparse
      const stLy=null; const stDiff=null;
      const aur = cur.u>0?cur.s/cur.u:null;
      return {dc,sales:cur.s,units:cur.u,aur,wd,wp,lyS:ly.s||null,lyU:ly.u||0,yd,yp,st,stLy,stDiff};
    }).sort((a,b)=>b.sales-a.sales);
  },[thisW,lastW,lyW,selCategory]);

  // Store drill-down for expanded DC
  const storeTable = useMemo(()=>{
    if(!expandedDC) return [];
    const m={}, p={};
    STORE_DATA.filter(d=>d[0]===latestFW&&d[1]===expandedDC).forEach(d=>{m[d[2]]=(m[d[2]]||{s:0,u:0});m[d[2]].s+=d[3];m[d[2]].u+=d[4];});
    if(prevFW) STORE_DATA.filter(d=>d[0]===prevFW&&d[1]===expandedDC).forEach(d=>{p[d[2]]=(p[d[2]]||{s:0,u:0});p[d[2]].s+=d[3];p[d[2]].u+=d[4];});
    return Object.entries(m).map(([store,cur])=>{
      const prv=p[store]||{s:0,u:0};
      const wd=prv.s>0?cur.s-prv.s:null, wp=prv.s>0?wd/prv.s*100:null;
      return {store,sales:cur.s,units:cur.u,wd,wp};
    }).sort((a,b)=>b.sales-a.sales);
  },[expandedDC,latestFW,prevFW]);

  // YTD
  const selFW25Set = useMemo(()=>new Set(selFW.map(fw=>FW25_MAP[fw]).filter(Boolean)),[selFW]);
  const allFW26 = useMemo(()=>filterAll26(),[selFW,selDC,selProd,selVendor,selCategory]);
  // FY25 YTD: when all categories selected include all FY25 products (incl. discontinued);
  // when a category is selected, filter FY25 by same CATEGORY_MAP
  const allFW25 = useMemo(()=>{
    const allCats = selCategory.length===ALL_CATEGORIES.length;
    return DATA25.filter(d=>{
      if(!selFW25Set.has(d[0])||!selDC.includes(d[1])) return false;
      if(allCats) return true;
      return selCategory.includes(CATEGORY_MAP[d[2]]);
    });
  },[selFW25Set,selDC,selCategory]);

  const ytd26=sumS(allFW26), ytd25=sumS25(allFW25);
  const ytdD=ytd26-ytd25, ytdP=ytd25>0?ytdD/ytd25*100:null;
  const ytdOutbound26 = allFW26.reduce(function(a,d){ var cases=d[6]; if(!cases||cases<=0) return a; return a+(cases*(PROD_PACK[d[2]]||10)); },0);
  const ytdST26=null; // DATA26 outbound too sparse
  const ytdST25=null; // FY25 outbound too sparse for reliable ST%

  const ytdByDC = useMemo(()=>{
    const m26={}, m25={};
    allFW26.forEach(d=>{m26[d[1]]=(m26[d[1]]||{s:0,u:0,o:0}); m26[d[1]].s+=d[4]; m26[d[1]].u+=d[5]; m26[d[1]].o+=d[6];});
    allFW25.forEach(d=>{m25[d[1]]=(m25[d[1]]||{s:0,u:0,o:0}); m25[d[1]].s+=d[3]; m25[d[1]].u+=d[4]; m25[d[1]].o+=d[5];});
    const dcs=[...new Set([...Object.keys(m26),...Object.keys(m25)])];
    return dcs.map(dc=>{
      const a=m26[dc]||{s:0,u:0,o:0}, b=m25[dc]||{s:0,u:0,o:0};
      const delta=a.s-b.s, pct=b.s>0?delta/b.s*100:null;
      const st26=calcST(a.u,a.o), st25=null, stD=null;
      const aur26=a.u>0?a.s/a.u:null;
      return {dc,s26:a.s,u26:a.u,aur26,s25:b.s,u25:b.u,delta,pct,st26,st25,stD};
    }).sort((a,b)=>sortYTDDC==="s26"?b.s26-a.s26:sortYTDDC==="delta"?(b.delta||0)-(a.delta||0):sortYTDDC==="st26"?(b.st26||0)-(a.st26||0):(b.pct||0)-(a.pct||0));
  },[allFW26,allFW25,sortYTDDC,selCategory]);

  const ytdByProd = useMemo(()=>{
    const m26={}, m25={};
    allFW26.forEach(d=>{m26[d[2]]=(m26[d[2]]||{s:0,u:0,o:0}); m26[d[2]].s+=d[4]; m26[d[2]].u+=d[5]; m26[d[2]].o+=d[6];});
    allFW25.forEach(d=>{m25[d[2]]=(m25[d[2]]||{s:0,u:0,o:0}); m25[d[2]].s+=d[3]; m25[d[2]].u+=d[4]; m25[d[2]].o+=d[5];});
    const prods=[...new Set([...Object.keys(m26),...Object.keys(m25)])];
    return prods.map(prod=>{
      const a=m26[prod]||{s:0,u:0,o:0}, b=m25[prod]||{s:0,u:0,o:0};
      const delta=a.s-b.s, pct=b.s>0?delta/b.s*100:null;
      const st26=calcST(a.u,a.o), st25=null, stD=null;
      const aur26=a.u>0?a.s/a.u:null;
      return {prod,s26:a.s,u26:a.u,aur26,s25:b.s,u25:b.u,delta,pct,st26,st25,stD};
    }).sort((a,b)=>sortYTDProd==="s26"?b.s26-a.s26:sortYTDProd==="delta"?(b.delta||0)-(a.delta||0):sortYTDProd==="st26"?(b.st26||0)-(a.st26||0):(b.pct||0)-(a.pct||0));
  },[allFW26,allFW25,sortYTDProd,selCategory]);

  // Trend chart data: weekly totals FY26 + FY25 by DC breakdown
  const trendData = useMemo(()=>{
    const allCats = selCategory.length===ALL_CATEGORIES.length;
    return ALL_FWS_FULL.map(fw=>{
      const rows26 = DATA26.filter(d=>d[0]===fw && selDC.includes(d[1]) && activeProdList.includes(d[2]) && selVendor.includes(d[3]));
      const fw25 = FW25_MAP[fw];
      const rows25 = DATA25.filter(d=>{
        if(d[0]!==fw25||!selDC.includes(d[1])) return false;
        if(allCats) return true;
        return selCategory.includes(CATEGORY_MAP[d[2]]);
      });
      const s26=rows26.reduce((a,d)=>a+d[4],0), u26=rows26.reduce((a,d)=>a+d[5],0);
      const s25=rows25.reduce((a,d)=>a+d[3],0), u25=rows25.reduce((a,d)=>a+d[4],0);
      // per-DC breakdown for FY26
      const byDC={};
      rows26.forEach(d=>{byDC[d[1]]=(byDC[d[1]]||{s:0,u:0});byDC[d[1]].s+=d[4];byDC[d[1]].u+=d[5];});
      return {fw, label:FW_LABEL(fw), s26, u26, s25, u25, byDC};
    });
  },[selDC,selVendor,activeProdList,selCategory]);

  // Store analytics: per-store summary for selected week
  const storeAnalytics = useMemo(()=>{
    const sortedSelWks = [...storeWkFilter].sort();
    const earliestIdx = ALL_FWS_FULL.indexOf(sortedSelWks[0]);
    const prev = earliestIdx > 0 ? ALL_FWS_FULL[earliestIdx-1] : null;
    const cur={}, prv={};
    STORE_DATA.filter(d=>storeWkFilter.includes(d[0])&&storeDCFilter.includes(d[1])).forEach(d=>{
      const key=d[1]+"|"+d[2];
      cur[key]=(cur[key]||{dc:d[1],store:d[2],s:0,u:0});
      cur[key].s+=d[3]; cur[key].u+=d[4];
    });
    if(prev) STORE_DATA.filter(d=>d[0]===prev&&storeDCFilter.includes(d[1])).forEach(d=>{
      const key=d[1]+"|"+d[2];
      prv[key]=(prv[key]||{s:0,u:0}); prv[key].s+=d[3]; prv[key].u+=d[4];
    });
    const rows = Object.entries(cur).map(([key,c])=>{
      const p=prv[key]||{s:0,u:0};
      const wd=p.s>0?c.s-p.s:null, wp=p.s>0?wd/p.s*100:null;
      const aur=c.u>0?c.s/c.u:null;
      return {dc:c.dc,store:c.store,sales:c.s,units:c.u,aur,wd,wp};
    });
    const isNumeric = /^\d+$/.test(storeSearch);
    const filtered = storeSearch ? rows.filter(r=>isNumeric ? String(r.store)===storeSearch : r.dc.toLowerCase().includes(storeSearch.toLowerCase())) : rows;
    return filtered.sort((a,b)=>
      storeSortKey==="sales"?b.sales-a.sales:
      storeSortKey==="units"?b.units-a.units:
      storeSortKey==="wd"?(b.wd||0)-(a.wd||0):
      storeSortKey==="wp"?(b.wp||0)-(a.wp||0):
      storeSortKey==="aur"?(b.aur||0)-(a.aur||0):
      b.sales-a.sales
    );
  },[storeWkFilter,storeDCFilter,storeSearch,storeSortKey]);

  // Store tab — By Product breakdown
  const storeByProduct = useMemo(()=>{
    const isStoreSearch = /^\d+$/.test(storeSearch) && storeSearch.length > 0;
    const cur={}, ly={};

    // Current: FY26 for selected weeks/DCs
    DATA26.filter(d=>storeWkFilter.includes(d[0])&&storeDCFilter.includes(d[1])&&selVendor.includes(d[3])).forEach(d=>{
      if(isStoreSearch) {
        const storeRow = STORE_DATA.find(s=>s[0]===d[0]&&s[1]===d[1]&&String(s[2])===storeSearch);
        if(!storeRow) return;
        const dcTotalUnits = DATA26.filter(r=>r[0]===d[0]&&r[1]===d[1]).reduce((a,r)=>a+r[5],0);
        const prodShare = dcTotalUnits>0 ? d[5]/dcTotalUnits : 0;
        cur[d[2]]=(cur[d[2]]||{s:0,u:0,o:0});
        cur[d[2]].s+=storeRow[3]*prodShare; cur[d[2]].u+=Math.round(storeRow[4]*prodShare); cur[d[2]].o+=d[6];
      } else {
        cur[d[2]]=(cur[d[2]]||{s:0,u:0,o:0});
        cur[d[2]].s+=d[4]; cur[d[2]].u+=d[5]; cur[d[2]].o+=d[6];
      }
    });

    // LY: FY25 for matching weeks
    const fw25set = new Set(storeWkFilter.map(fw=>FW25_MAP[fw]).filter(Boolean));
    DATA25.filter(d=>fw25set.has(d[0])&&storeDCFilter.includes(d[1])).forEach(d=>{
      ly[d[2]]=(ly[d[2]]||{s:0,u:0});
      ly[d[2]].s+=d[3]; ly[d[2]].u+=d[4];
    });

    return Object.entries(cur).map(([prod,c])=>{
      const l=ly[prod]||{s:0,u:0};
      const yoyD=l.s>0?c.s-l.s:null, yoyP=l.s>0?yoyD/l.s*100:null;
      const aur=c.u>0?c.s/c.u:null;
      const st=null; // DATA26 outbound too sparse
      return {prod,sales:c.s,units:c.u,aur,yoyD,yoyP,lyS:l.s,st};
    }).filter(r=>r.sales>0).sort((a,b)=>b.sales-a.sales);
  },[storeWkFilter,storeDCFilter,selVendor,storeSearch]);

  // ── ALLOCATIONS ──────────────────────────────────────────────────────────────
  const SAFETY = 1.15;
  const MIN_DELIVERY_WKS = allocCategory.every(c=>c==="3inch"||c==="cascades"||c==="fused") ? 1 : 2;
  const CONSEC_HIGH_WKS = 3;
  const HIGH_ST = 85;
  const LOW_ST = 60;       // skip threshold — unchanged
  const STD_FLOOR = 60;    // standard floor back to 60
  const MIN_UNITS_HIGH = 15; // min units sold in baseline to qualify for +2
  const TREND_WKS = 3;     // look-back window for trend bonus
  const TREND_MIN = 2;     // weeks ≥85% in that window = Trending
  const VOL_HIGH_ST = 78;  // high-volume stores get Watch at this ST%
  const VOL_TOP_FRAC = 1/3;// top fraction by avg weekly sales = high volume

  const allocFWs = useMemo(()=>{
    if(allocBaseline==="last4") return ALL_FWS_FULL.slice(-4);
    if(allocBaseline==="last8") return ALL_FWS_FULL.slice(-8);
    if(allocBaseline==="custom") return ALL_FWS_FULL.filter(fw=>fw>=allocCustomFrom&&fw<=allocCustomTo);
    return ALL_FWS_FULL;
  },[allocBaseline, allocCustomFrom, allocCustomTo]);

  const allocData = useMemo(()=>{
    const allResults = [];
    for(const catKey of allocCategory) {
    const catDef = ALLOC_CATEGORIES.find(c=>c.key===catKey);
    if(!catDef) continue;

    // Pre-index DATA26 by "fw|dc" for fast lookups
    const d26idx = {};
    DATA26.forEach(d=>{
      if(!catDef.prods.includes(d[2])) return;
      const k = d[0]+"|"+d[1];
      if(!d26idx[k]) d26idx[k]=[];
      d26idx[k].push(d);
    });

    // Pre-compute per-DC delivery weeks, sales, outbound, ST% for all FWs
    const dcCache = {};
    const allDCs = [...new Set(DATA26.map(d=>d[1]))];
    allDCs.forEach(dc=>{
      dcCache[dc] = {};
      ALL_FWS_FULL.forEach(fw=>{
        const rows = d26idx[fw+"|"+dc]||[];
        const hasOut = rows.some(d=>d[6]>0);
        const sales = rows.reduce((a,d)=>a+d[5],0);
        const out = rows.reduce((a,d)=>a+d[6],0);
        const st = out>0 ? sales/out*100 : null;
        const vendor = rows.find(d=>d[6]>0)?.[3]||null;
        dcCache[dc][fw] = {hasOut, sales, out, st, vendor};
      });
    });

    // Pre-compute storeCount per fw+dc from STORE_DATA
    const storeCountIdx = {};
    STORE_DATA.forEach(d=>{
      const k = d[0]+"|"+d[1];
      storeCountIdx[k] = (storeCountIdx[k]||0)+1;
    });

    // Pre-index STORE_DATA by "fw|dc|store" for fast per-store sales lookup
    const storeDataIdx = {};
    STORE_DATA.forEach(d=>{
      storeDataIdx[d[0]+"|"+d[1]+"|"+d[2]] = [d[3], d[4]]; // [sales, all-product-units]
    });

    // Pre-index DC total units per fw+dc for category proportioning
    const dcUnitsIdx = {};
    DATA26.forEach(d=>{
      if(!catDef.prods.includes(d[2])) return;
      const k = d[0]+"|"+d[1];
      dcUnitsIdx[k] = (dcUnitsIdx[k]||0)+d[5];
    });

    // Pre-index DC total sales per fw+dc for proportioning
    const dcTotalSalesIdx = {};
    STORE_DATA.forEach(d=>{
      const k = d[0]+"|"+d[1];
      dcTotalSalesIdx[k] = (dcTotalSalesIdx[k]||0)+d[3];
    });

    // get all stores in selected DCs
    const storeKeys = new Set();
    STORE_DATA.forEach(d=>{ if(allocDC.includes(d[1])) storeKeys.add(d[1]+"|"+d[2]); });

    // Pre-compute per-DC volume threshold (top 1/3 by avg weekly sales)
    const dcVolThreshold = {};
    allocDC.forEach(dc=>{
      const storeSalesArr = [];
      storeKeys.forEach(key=>{
        const [kDC, kStore] = key.split("|");
        if(kDC!==dc) return;
        const dcFWs2 = dcCache[dc]||{};
        const delWks = allocFWs.filter(fw=>dcFWs2[fw]?.hasOut);
        if(delWks.length===0) return;
        const avg = delWks.reduce((a,fw)=>a+(storeDataIdx[fw+"|"+dc+"|"+kStore]||[0,0])[0],0)/delWks.length;
        storeSalesArr.push(avg);
      });
      storeSalesArr.sort((a,b)=>b-a);
      const cutoffIdx = Math.floor(storeSalesArr.length * VOL_TOP_FRAC);
      dcVolThreshold[dc] = storeSalesArr[cutoffIdx] || 0;
    });

    const catRows = [...storeKeys].map(key=>{
      const [dc, store] = key.split("|");
      const dcFWs = dcCache[dc]||{};

      // delivery weeks within baseline window (DC must have had outbound that week)
      const deliveryWks = allocFWs.filter(fw=> dcFWs[fw]?.hasOut);

      if(deliveryWks.length < MIN_DELIVERY_WKS) {
        return {store,dc,catKey,catLabel:catDef.label,insuff:true,avgSales:null,avgST:null,piecesSold:0,piecesReceived:0,casesReceived:0,consecHigh:0,currentCases:null,recCases:null,status:"insuff",packSize:catDef.packSize||10};
      }

      // Avg wkly sales = this store's own sales on delivery weeks
      const storeSalesByWk = deliveryWks.map(fw=> (storeDataIdx[fw+"|"+dc+"|"+store]||[0,0])[0]);
      const avgSales = storeSalesByWk.reduce((a,v)=>a+v,0)/storeSalesByWk.length;

      // Units sold = category-specific from STORE_CAT_UNITS (not all-product total)
      const catUnitsForStore = STORE_CAT_UNITS[catKey]?.[store]||{};
      // Sum units across ALL baseline weeks (not just delivery weeks)
      const unitsSold = allocFWs.reduce((a,fw)=>{
        return a + (catUnitsForStore[fw]?.[dc]||0);
      }, 0);

      // DC-level ST% (fallback)
      const stByWk = deliveryWks.map(fw=> dcFWs[fw].st);
      const validST = stByWk.filter(v=>v!=null);
      const avgST = validST.length>0 ? validST.reduce((a,v)=>a+v,0)/validST.length : null;

      // consecutive high ST% weeks using direct units/outbound
      let consecHigh = 0;
      const catOut = STORE_OUTBOUND[catKey]||{};
      const allDeliveryWks = ALL_FWS_FULL.filter(fw=> dcCache[dc]?.[fw]?.hasOut).reverse();
      for(const fw of allDeliveryWks) {
        const ob = catOut[store]?.[fw];
        if(!ob||ob[1]===0) continue;
        const storeUnits = STORE_CAT_UNITS[catKey]?.[store]?.[fw]?.[dc]||0;
        const st = ob[1]>0 ? storeUnits/ob[1]*100 : null;
        if(st!=null && st>=HIGH_ST) consecHigh++;
        else break;
      }

      // trend bonus: count weeks ≥85% in last TREND_WKS delivery weeks
      const recentDeliveryWks = allDeliveryWks.slice(0, TREND_WKS);
      const highWksInWindow = recentDeliveryWks.filter(fw=>{
        const ob = catOut[store]?.[fw];
        if(!ob||ob[1]===0) return false;
        const storeUnits = STORE_CAT_UNITS[catKey]?.[store]?.[fw]?.[dc]||0;
        return ob[1]>0 && storeUnits/ob[1]*100 >= HIGH_ST;
      }).length;
      const isTrending = highWksInWindow >= TREND_MIN && consecHigh < CONSEC_HIGH_WKS;

      // current cases — most recent delivery week
      const mostRecentFW = [...ALL_FWS_FULL].reverse().find(fw=> dcFWs[fw]?.hasOut);
      let currentCases = 0, currentVendor = null;
      if(mostRecentFW) {
        const f = dcFWs[mostRecentFW];
        currentVendor = f.vendor;
        const packSz = catDef.packByVendor?(catDef.packByVendor[currentVendor]||10):catDef.packSize;
        const storeCount = storeCountIdx[mostRecentFW+"|"+dc]||1;
        currentCases = packSz>0 ? Math.round((f.out/storeCount)/packSz) : 0;
      }
      const packSize = catDef.packByVendor?(catDef.packByVendor[currentVendor]||10):catDef.packSize;

      // Pieces received = sum across baseline delivery weeks for this store + category
      const catOutbound = STORE_OUTBOUND[catKey]||{};
      const piecesReceived = deliveryWks.reduce((a,fw)=>{
        const ob = catOutbound[store]?.[fw];
        return a + (ob ? ob[1] : 0);
      }, 0);
      const casesReceived = deliveryWks.reduce((a,fw)=>{
        const ob = catOutbound[store]?.[fw];
        return a + (ob ? ob[0] : 0);
      }, 0);

      // Store ST% = units sold / pieces received (cases x pack)
      const storeSTPct = piecesReceived>0 ? unitsSold/piecesReceived*100 : null;
      const stForRec = storeSTPct!=null ? storeSTPct : (piecesReceived>0 ? avgST : null);

      // Volume tier: is this store in top 1/3 by avg sales for its DC?
      const isHighVol = avgSales >= (dcVolThreshold[dc]||0);

      let recCases, status;
      if(stForRec===null || stForRec<LOW_ST) {
        // Below hard skip threshold (unchanged at 60%)
        recCases=0; status="skip";
      } else if(stForRec<STD_FLOOR) {
        // 60–69%: now Skip (raised standard floor)
        recCases=0; status="skip";
      } else if(catDef.cycle==="weekly") {
        if(consecHigh>=CONSEC_HIGH_WKS && unitsSold>=MIN_UNITS_HIGH) {
          // 3+ consec weeks ≥85% AND ≥15 units sold → High Performer
          recCases=2; status="high";
        } else if(isTrending) {
          // 2 of last 3 weeks ≥85% (not yet consec) → Trending +2
          recCases=2; status="trending";
        } else if(stForRec>=HIGH_ST) {
          // ≥85% but not consec/trending → Watch
          recCases=1; status="watch";
        } else if(isHighVol && stForRec>=VOL_HIGH_ST) {
          // High-volume store ≥78% → Watch
          recCases=1; status="watch";
        } else {
          // 70–84% standard
          recCases=1; status="standard";
        }
      } else {
        recCases=1; status="standard";
      }

      return {store,dc,catKey,catLabel:catDef.label,insuff:false,avgSales,avgST,piecesSold:unitsSold,piecesReceived,casesReceived,consecHigh,currentCases,recCases,status,packSize,isTrending,isHighVol};
    }).filter(r=>allocDC.includes(r.dc))
      .sort((a,b)=>a.dc===b.dc?Number(a.store)-Number(b.store):a.dc.localeCompare(b.dc));
    allResults.push(...catRows);
    } // end for catKey
    return allResults;
  },[allocFWs,allocCategory,allocDC]);

  // ── DISTRICT COMPARISON ──────────────────────────────────────────────────────
  const districtData = useMemo(()=>{
    const fw25set = new Set(selFW.map(fw=>FW25_MAP[fw]).filter(Boolean));
    // FY26: aggregate STORE_DATA by district
    const m26={}, m25={};
    STORE_DATA.filter(d=>selFW.includes(d[0])&&selDC.includes(d[1])).forEach(d=>{
      const meta = STORE_META[d[2]];
      if(!meta) return;
      const key = meta.region+"|||"+meta.district;
      m26[key] = m26[key]||{region:meta.region,district:meta.district,s:0,u:0,stores:new Set()};
      m26[key].s+=d[3]; m26[key].u+=d[4]; m26[key].stores.add(d[2]);
    });
    // FY25: aggregate STORE_DATA25 by district for matching weeks
    STORE_DATA25.filter(d=>fw25set.has(d[0])&&selDC.includes(d[1])).forEach(d=>{
      const meta = STORE_META[d[2]];
      if(!meta) return;
      const key = meta.region+"|||"+meta.district;
      m25[key] = m25[key]||{s:0,u:0};
      m25[key].s+=d[3]; m25[key].u+=d[4];
    });
    // Build rows
    const rows = Object.entries(m26).map(([key,c])=>{
      const ly = m25[key]||{s:0,u:0};
      const yoyD = c.s-ly.s, yoyP = ly.s>0?yoyD/ly.s*100:null;
      const aur = c.u>0?c.s/c.u:null;
      return {region:c.region,district:c.district,stores:c.stores.size,s26:c.s,u26:c.u,aur,s25:ly.s,yoyD,yoyP};
    });
    // Sort within each region group
    const sorted = rows.sort((a,b)=>{
      if(a.region!==b.region) return a.region.localeCompare(b.region);
      if(districtSort==="s26") return b.s26-a.s26;
      if(districtSort==="yoyD") return (b.yoyD||0)-(a.yoyD||0);
      if(districtSort==="yoyP") return (b.yoyP||0)-(a.yoyP||0);
      return b.s26-a.s26;
    });
    // Group by region
    const byRegion={};
    sorted.forEach(r=>{
      byRegion[r.region]=byRegion[r.region]||{rows:[],s26:0,s25:0,u26:0,stores:0};
      byRegion[r.region].rows.push(r);
      byRegion[r.region].s26+=r.s26; byRegion[r.region].s25+=r.s25;
      byRegion[r.region].u26+=r.u26; byRegion[r.region].stores+=r.stores;
    });
    return byRegion;
  },[selFW,selDC,districtSort]);

  // ── TOOL DEFINITIONS ────────────────────────────────────────────────────────
  const CHAT_TOOLS = [
    {name:"get_store_detail",description:"Get detailed sales, ST%, pieces received/sold, and allocation status for a specific store. Use when asked about a specific store number.",input_schema:{type:"object",properties:{store:{type:"string",description:"Store number e.g. '202'"},category:{type:"string",description:"Category key: 5inch, 3inch, fused, cascades. Default: 5inch"},fws:{type:"array",items:{type:"number"},description:"Fiscal weeks to include e.g. [202609,202610,202611,202612]. Default: last 4 weeks"}},required:["store"]}},
    {name:"get_dc_summary",description:"Get all stores in a DC ranked by ST%, with sales and allocation status. Use when asked about a specific DC.",input_schema:{type:"object",properties:{dc:{type:"string",description:"DC name e.g. FULRTNCADC"},category:{type:"string",description:"Category key: 5inch, 3inch, fused, cascades. Default: 5inch"},top_n:{type:"number",description:"Number of top/bottom stores to return. Default: 10"}},required:["dc"]}},
    {name:"get_district_detail",description:"Get all stores in a district with FY26 vs FY25 YoY sales comparison. Use when asked about a district.",input_schema:{type:"object",properties:{district:{type:"string",description:"District name e.g. D55 or D23"}},required:["district"]}},
    {name:"get_fw_breakdown",description:"Get week-by-week sales and units for a product category and/or DC. Use when asked about trends or specific fiscal weeks.",input_schema:{type:"object",properties:{dc:{type:"string",description:"DC name, or 'ALL' for all DCs"},category:{type:"string",description:"Category: 5inch, 3inch, fused, cascades, or product name like PLANT-5-ORCHID"},fws:{type:"array",items:{type:"number"},description:"Specific fiscal weeks. Default: all FW01-FW12"}},required:[]}},
    {name:"get_allocation_recs",description:"Get allocation recommendations: which stores qualify for +1 or +2 cases based on ST% and consecutive high weeks. Use when asked about recommendations or who should get more cases.",input_schema:{type:"object",properties:{dc:{type:"string",description:"DC name, or 'ALL' for all DCs. Default: ALL"},category:{type:"string",description:"Category key. Default: 5inch"},status:{type:"string",description:"Filter by status: high_performer, watch, standard, skip, or ALL. Default: ALL"}},required:[]}},
    {name:"get_corrections_detail",description:"Get the full corrections log with store-level detail. Use when asked about corrections or overrides.",input_schema:{type:"object",properties:{dc:{type:"string",description:"DC name or ALL"},product:{type:"string",description:"Product name filter or ALL"}},required:[]}},
  ];

  const executeTool = (name, input) => {
    const prods5 = ["PLANT-5-ORCHID","PLANT-ORCHID","ORCHID-PREMIUM-CERAMIC","ORCHID-PLANT","ORCHID-COLOR-EVERYDAY-5 IN","ORCHID-LARGE WHITE"];
    const prods3 = ["PLANT-ORCHID-SMALL","ORCHID-SMALL"];
    const prodsF = ["PLANT-ORCHID-FUSED","ORCHID-FUSED-COLORED","ORCHID-CASCADE-FUSED"];
    const prodsC = ["PLANT-ORCHID-CASCADE-PREMIUM","ORCHID-CASCADE","ORCHID-WATERFALL-PREMIUM-5IN"];
    const catProds = {"5inch":prods5, "3inch":prods3, "fused":prodsF, "cascades":prodsC};
    const last4 = ALL_FWS_FULL.slice(-4);

    if(name==="get_store_detail"){
      const {store, category="5inch", fws=last4} = input;
      const meta = STORE_META[store];
      if(!meta) return `Store ${store} not found.`;
      const dc = meta.dc;
      const ob = STORE_OUTBOUND[category]?.[store]||{};
      const rows = fws.map(fw=>{
        const obFw = ob[fw]||[0,0];
        const sd = STORE_DATA.find(d=>d[0]===fw&&d[1]===dc&&String(d[2])===String(store));
        const dcSales = STORE_DATA.filter(d=>d[0]===fw&&d[1]===dc).reduce((a,d)=>a+d[3],0);
        const dcUnits = DATA26.filter(d=>d[0]===fw&&d[1]===dc&&(catProds[category]||prods5).includes(d[2])).reduce((a,d)=>a+d[5],0);
        const sold = (sd&&dcSales>0&&dcUnits>0)?Math.round((sd[3]/dcSales)*dcUnits):0;
        const st = obFw[1]>0?(sold/obFw[1]*100).toFixed(1):null;
        return `FW${String(fw).slice(-2)}: Sales $${sd?Math.round(sd[3]).toLocaleString():0}, Pieces Rcvd ${obFw[1]}, Sold ~${sold}, ST% ${st?st+'%':'N/A'}`;
      });
      return `Store #${store} — ${meta.name}\nDC: ${dc} | District: ${meta.district} | Region: ${meta.region}\n\n${rows.join('\n')}`;
    }

    if(name==="get_dc_summary"){
      const {dc, category="5inch", top_n=10} = input;
      const stores = (DC_STORES[dc]||[]).map(s=>String(s));
      if(!stores.length) return `DC ${dc} not found.`;
      const stList = [];
      stores.forEach(store=>{
        const ob = STORE_OUTBOUND[category]?.[store]||{};
        let totalPieces=0, totalSold=0, totalSales=0;
        last4.forEach(fw=>{
          const obFw = ob[fw]||[0,0]; totalPieces+=obFw[1];
          const sd = STORE_DATA.find(d=>d[0]===fw&&d[1]===dc&&String(d[2])===String(store));
          const dcSales = STORE_DATA.filter(d=>d[0]===fw&&d[1]===dc).reduce((a,d)=>a+d[3],0);
          const dcUnits = DATA26.filter(d=>d[0]===fw&&d[1]===dc&&(catProds[category]||prods5).includes(d[2])).reduce((a,d)=>a+d[5],0);
          if(sd){totalSales+=sd[3];if(dcSales>0&&dcUnits>0)totalSold+=Math.round((sd[3]/dcSales)*dcUnits);}
        });
        const st = totalPieces>0?(totalSold/totalPieces*100):null;
        stList.push({store,name:STORE_META[store]?.name||store,st,sales:totalSales,pieces:totalPieces});
      });
      stList.sort((a,b)=>(b.st||0)-(a.st||0));
      const top = stList.slice(0,top_n);
      const bottom = stList.slice(-top_n).reverse();
      return `DC: ${dc} | ${stores.length} stores | Category: ${category}\n\nTOP ${top_n} by ST%:\n${top.map(s=>`#${s.store} ${s.name}: ST% ${s.st?s.st.toFixed(1)+'%':'N/A'}, Sales $${Math.round(s.sales).toLocaleString()}`).join('\n')}\n\nBOTTOM ${top_n} by ST%:\n${bottom.map(s=>`#${s.store} ${s.name}: ST% ${s.st?s.st.toFixed(1)+'%':'N/A'}, Sales $${Math.round(s.sales).toLocaleString()}`).join('\n')}`;
    }

    if(name==="get_district_detail"){
      const {district} = input;
      const distStores = Object.entries(STORE_META).filter(([,m])=>m.district===district).map(([s])=>s);
      if(!distStores.length) return `District ${district} not found.`;
      const fw25set = new Set(ALL_FWS_FULL.map(fw=>FW25_MAP[fw]).filter(Boolean));
      const rows = distStores.map(store=>{
        const meta = STORE_META[store];
        const s26 = STORE_DATA.filter(d=>d[2]===store).reduce((a,d)=>a+d[3],0);
        const s25 = STORE_DATA25.filter(d=>d[2]===store&&fw25set.has(d[0])).reduce((a,d)=>a+d[3],0);
        const yoy = s25>0?((s26-s25)/s25*100).toFixed(1):null;
        return `#${store} ${meta.name}: FY26 $${Math.round(s26).toLocaleString()} vs FY25 $${Math.round(s25).toLocaleString()} = ${yoy?yoy+'%':'N/A'} YoY`;
      }).sort((a,b)=>a.localeCompare(b));
      const totS26 = distStores.reduce((a,s)=>a+STORE_DATA.filter(d=>d[2]===s).reduce((b,d)=>b+d[3],0),0);
      const totS25 = distStores.reduce((a,s)=>a+STORE_DATA25.filter(d=>d[2]===s&&fw25set.has(d[0])).reduce((b,d)=>b+d[3],0),0);
      const totYoy = totS25>0?((totS26-totS25)/totS25*100).toFixed(1):null;
      return `District: ${district} | ${distStores.length} stores\nTotal: FY26 $${Math.round(totS26).toLocaleString()} vs FY25 $${Math.round(totS25).toLocaleString()} = ${totYoy?totYoy+'%':'N/A'} YoY\n\n${rows.join('\n')}`;
    }

    if(name==="get_fw_breakdown"){
      const {dc="ALL", category="5inch", fws=ALL_FWS_FULL} = input;
      const prods = catProds[category]||[category];
      const rows = fws.map(fw=>{
        const filtered = dc==="ALL"
          ? DATA26.filter(d=>d[0]===fw&&prods.includes(d[2]))
          : DATA26.filter(d=>d[0]===fw&&d[1]===dc&&prods.includes(d[2]));
        const s26 = filtered.reduce((a,d)=>a+d[4],0);
        const u26 = filtered.reduce((a,d)=>a+d[5],0);
        const fw25 = FW25_MAP[fw];
        const f25 = fw25?(dc==="ALL"?DATA25.filter(d=>d[0]===fw25&&prods.some(p=>d[2]===p)):DATA25.filter(d=>d[0]===fw25&&d[1]===dc&&prods.some(p=>d[2]===p))):[];
        const s25 = f25.reduce((a,d)=>a+d[3],0);
        const yoy = s25>0?((s26-s25)/s25*100).toFixed(1):null;
        return `FW${String(fw).slice(-2)}: $${Math.round(s26).toLocaleString()} (${u26} units)${yoy?' | YoY: '+yoy+'%':''}`;
      });
      return `${category} sales ${dc==="ALL"?"all DCs":dc} FW01-FW12:\n${rows.join('\n')}`;
    }

    if(name==="get_allocation_recs"){
      const {dc="ALL", category="5inch", status="ALL"} = input;
      const ob = STORE_OUTBOUND[category]||{};
      const stores = dc==="ALL" ? Object.keys(STORE_META) : (DC_STORES[dc]||[]).map(String);
      const results = [];
      stores.forEach(store=>{
        const meta = STORE_META[store]; if(!meta) return;
        const storeDC = meta.dc;
        let totalPieces=0, totalSold=0; let consec=0;
        for(const fw of [...ALL_FWS_FULL].reverse()){
          const obFw = ob[store]?.[fw]||[0,0]; if(!obFw[1]) break;
          const sd = STORE_DATA.find(d=>d[0]===fw&&d[1]===storeDC&&String(d[2])===String(store));
          const dcSales = STORE_DATA.filter(d=>d[0]===fw&&d[1]===storeDC).reduce((a,d)=>a+d[3],0);
          const dcUnits = DATA26.filter(d=>d[0]===fw&&d[1]===storeDC&&(catProds[category]||prods5).includes(d[2])).reduce((a,d)=>a+d[5],0);
          if(sd&&dcSales>0&&dcUnits>0){const st=Math.round((sd[3]/dcSales)*dcUnits)/obFw[1]*100;if(st>=85)consec++;else break;}else break;
        }
        last4.forEach(fw=>{
          const obFw = ob[store]?.[fw]||[0,0]; totalPieces+=obFw[1];
          const sd = STORE_DATA.find(d=>d[0]===fw&&d[1]===storeDC&&String(d[2])===String(store));
          const dcSales = STORE_DATA.filter(d=>d[0]===fw&&d[1]===storeDC).reduce((a,d)=>a+d[3],0);
          const dcUnits = DATA26.filter(d=>d[0]===fw&&d[1]===storeDC&&(catProds[category]||prods5).includes(d[2])).reduce((a,d)=>a+d[5],0);
          if(sd&&dcSales>0&&dcUnits>0)totalSold+=Math.round((sd[3]/dcSales)*dcUnits);
        });
        if(totalPieces===0) return;
        const st = totalSold/totalPieces*100;
        let rec; if(st<60)rec="skip";else if(st<85)rec="standard";else if(consec>=3)rec="high_performer";else rec="watch";
        if(status!=="ALL"&&rec!==status) return;
        const cases = rec==="high_performer"?"+2":rec==="skip"?"0":"+1";
        results.push(`#${store} ${meta.name} (${storeDC}): ST% ${st.toFixed(1)}%, ${consec} consec → ${cases} cases [${rec}]`);
      });
      return `Allocation recs — ${category}, ${dc==="ALL"?"all DCs":dc}:\n${results.length} stores\n\n${results.slice(0,30).join('\n')}${results.length>30?`\n...and ${results.length-30} more`:''}`;
    }

    if(name==="get_corrections_detail"){
      const {dc="ALL", product="ALL"} = input;
      const filtered = CORRECTIONS_LOG.filter(r=>(dc==="ALL"||r.dc===dc)&&(product==="ALL"||r.product===product));
      const summary = {};
      filtered.forEach(r=>{
        const k=r.dc+"|"+r.product;
        summary[k]=summary[k]||{dc:r.dc,product:r.product,stores:0,origTotal:0,corrTotal:0};
        summary[k].stores++; summary[k].origTotal+=r.orig; summary[k].corrTotal+=r.corrected;
      });
      const rows = Object.values(summary).map(s=>`${s.dc} | ${s.product}: ${s.stores} stores, ${s.origTotal}→${s.corrTotal} cases (${s.corrTotal-s.origTotal})`);
      return `Corrections (WK12/13/14):\n${rows.join('\n')}\n\nTotal: ${filtered.length} corrections, ${filtered.reduce((a,r)=>a+r.diff,0)} case delta`;
    }

    return `Tool ${name} not implemented.`;
  };

  const handleChatSend = async (q) => {
    if(!q||chatLoading) return;
    setChatInput("");
    setChatMessages(prev=>[...prev,{role:"user",content:q}]);
    setChatLoading(true);
    try{
      const fw25set = new Set(ALL_FWS_FULL.map(fw=>FW25_MAP[fw]).filter(Boolean));
      const distYoY={};
      STORE_DATA.forEach(d=>{const m=STORE_META[d[2]];if(!m)return;distYoY[m.district]=distYoY[m.district]||{s26:0,s25:0,region:m.region};distYoY[m.district].s26+=d[3];});
      STORE_DATA25.filter(d=>fw25set.has(d[0])).forEach(d=>{const m=STORE_META[d[2]];if(!m)return;if(distYoY[m.district])distYoY[m.district].s25+=d[3];});
      const distSummary=Object.entries(distYoY).map(([d,v])=>({district:d,region:v.region,s26:Math.round(v.s26),s25:Math.round(v.s25),yoyP:v.s25>0?((v.s26-v.s25)/v.s25*100).toFixed(1):null})).sort((a,b)=>parseFloat(b.yoyP||0)-parseFloat(a.yoyP||0));

      const systemPrompt = `You are a floral sales data analyst for Sprouts Farmers Market. You have access to FY2026 and FY2025 floral data through tools.

OVERVIEW:
- FY26 YTD Sales (FW01-FW12): $${(DATA26.reduce((a,d)=>a+d[4],0)/1000).toFixed(1)}K
- FY25 comparison: $${(DATA25.reduce((a,d)=>a+d[3],0)/1000).toFixed(1)}K
- DCs: ${[...new Set(DATA26.map(d=>d[1]))].join(', ')}
- Total stores: ${Object.keys(STORE_META).length}

DISTRICT YOY (top 5 / bottom 5):
Best: ${distSummary.slice(0,5).map(d=>`${d.district}(${d.yoyP}%)`).join(', ')}
Worst: ${distSummary.slice(-5).map(d=>`${d.district}(${d.yoyP}%)`).join(', ')}

CORRECTIONS: WK12 FULRTNCADC 120 corrections. WK13 FULRTNCADC/PHOENXAZDC/TRACYCADC5 corrections. WK14 FULRTNCADC/PHOENXAZDC/TRACYCADC126 corrections (FY26 outbound missing). Total: 251 corrections.

Use tools to look up specific stores, DCs, districts, or weekly trends. Be concise and use real numbers.`;

      // Multi-turn tool use loop
      let messages = [...chatMessages.filter(m=>typeof m.content==='string'), {role:"user",content:q}];
      let finalReply = "";
      let iterations = 0;

      while(iterations < 5){
        iterations++;
        const resp = await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":ANTHROPIC_KEY,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-sonnet-4-5",max_tokens:1024,system:systemPrompt,messages,tools:CHAT_TOOLS})});
        const data = await resp.json();
        if(data.error) { finalReply = data.error.message||"API error."; break; }

        const textBlock = data.content?.find(c=>c.type==="text");
        const toolUseBlocks = data.content?.filter(c=>c.type==="tool_use")||[];

        if(data.stop_reason==="end_turn"||toolUseBlocks.length===0){
          finalReply = textBlock?.text||"No response.";
          break;
        }

        // Execute tools and build tool_results
        const toolResults = toolUseBlocks.map(tu=>({
          type:"tool_result",
          tool_use_id:tu.id,
          content:executeTool(tu.name, tu.input)
        }));

        // Add assistant response + tool results to messages
        messages = [...messages,
          {role:"assistant",content:data.content},
          {role:"user",content:toolResults}
        ];
      }

      setChatMessages(prev=>[...prev,{role:"assistant",content:finalReply}]);
    }catch(err){
      setChatMessages(prev=>[...prev,{role:"assistant",content:"Error: "+err.message}]);
    }
    setChatLoading(false);
  };

  // ── INSIGHTS DATA ────────────────────────────────────────────────────────────
  const insightsData = useMemo(()=>{
    const last4 = ALL_FWS_FULL.slice(-4);
    const prods5 = ["PLANT-5-ORCHID","PLANT-ORCHID","ORCHID-PREMIUM-CERAMIC","ORCHID-PLANT","ORCHID-COLOR-EVERYDAY-5 IN","ORCHID-LARGE WHITE"];

    // Pre-index for speed
    const storeDataIdx = {};
    STORE_DATA.forEach(d=>{ storeDataIdx[d[0]+"|"+d[1]+"|"+d[2]]=[d[3],d[4]]; });
    const dcTotalSalesIdx = {};
    STORE_DATA.forEach(d=>{ const k=d[0]+"|"+d[1]; dcTotalSalesIdx[k]=(dcTotalSalesIdx[k]||0)+d[3]; });
    const dcUnitsIdx = {};
    DATA26.forEach(d=>{ if(!prods5.includes(d[2])) return; const k=d[0]+"|"+d[1]; dcUnitsIdx[k]=(dcUnitsIdx[k]||0)+d[5]; });

    // Store ST% (5inch, last 4 wks)
    const storeSTList = [];
    const ob5 = STORE_OUTBOUND["5inch"]||{};
    Object.keys(ob5).forEach(store=>{
      const meta = STORE_META[store]; if(!meta) return;
      const dc = meta.dc;
      let totalPieces=0, totalSold=0;
      last4.forEach(fw=>{
        const ob = ob5[store]?.[fw]; if(!ob) return;
        totalPieces += ob[1];
        const sd = storeDataIdx[fw+"|"+dc+"|"+store];
        const dcSales = dcTotalSalesIdx[fw+"|"+dc]||0;
        const dcUnits = dcUnitsIdx[fw+"|"+dc]||0;
        if(sd&&dcSales>0&&dcUnits>0) totalSold += Math.round((sd[0]/dcSales)*dcUnits);
      });
      if(totalPieces>0) storeSTList.push({store,name:meta.name,dc,st:totalSold/totalPieces*100});
    });
    storeSTList.sort((a,b)=>b.st-a.st);

    // High performers (3+ consec store ST% ≥ 85%)
    const highPerf = [];
    Object.keys(ob5).forEach(store=>{
      const meta = STORE_META[store]; if(!meta) return;
      const dc = meta.dc;
      let consec=0;
      for(const fw of [...ALL_FWS_FULL].reverse()){
        const ob = ob5[store]?.[fw]; if(!ob||ob[1]===0) break;
        const sd = storeDataIdx[fw+"|"+dc+"|"+store];
        const dcSales = dcTotalSalesIdx[fw+"|"+dc]||0;
        const dcUnits = dcUnitsIdx[fw+"|"+dc]||0;
        if(sd&&dcSales>0&&dcUnits>0){
          const st = Math.round((sd[0]/dcSales)*dcUnits)/ob[1]*100;
          if(st>=85) consec++; else break;
        } else break;
      }
      if(consec>=3) highPerf.push({store,name:meta.name,dc,consec});
    });
    highPerf.sort((a,b)=>b.consec-a.consec);

    // Stores with 0 pieces received last 4 wks
    const zeroPieces = Object.keys(STORE_META).filter(store=>{
      const total = last4.reduce((a,fw)=>{ const ob=ob5[store]?.[fw]; return a+(ob?ob[1]:0); },0);
      return total===0 && STORE_DATA.some(d=>d[2]===store);
    }).slice(0,20);

    // Worst districts YoY
    const fw25set = new Set(ALL_FWS_FULL.map(fw=>FW25_MAP[fw]).filter(Boolean));
    const distYoY = {};
    STORE_DATA.forEach(d=>{ const m=STORE_META[d[2]]; if(!m) return; distYoY[m.district]=distYoY[m.district]||{s26:0,s25:0}; distYoY[m.district].s26+=d[3]; });
    STORE_DATA25.filter(d=>fw25set.has(d[0])).forEach(d=>{ const m=STORE_META[d[2]]; if(!m) return; if(distYoY[m.district]) distYoY[m.district].s25+=d[3]; });
    const worstDist = Object.entries(distYoY).filter(([,v])=>v.s25>0).map(([d,v])=>({district:d,yoyP:(v.s26-v.s25)/v.s25*100,yoyD:v.s26-v.s25})).sort((a,b)=>a.yoyP-b.yoyP).slice(0,5);

    // DC avg store ST%
    const dcSTMap = {};
    storeSTList.forEach(r=>{ dcSTMap[r.dc]=dcSTMap[r.dc]||{sum:0,n:0}; dcSTMap[r.dc].sum+=r.st; dcSTMap[r.dc].n++; });
    const dcSTRanked = Object.entries(dcSTMap).map(([dc,v])=>({dc,avg:v.sum/v.n})).sort((a,b)=>b.avg-a.avg);

    return {storeSTList, highPerf, zeroPieces, worstDist, dcSTRanked};
  },[]);

  // Export date — default to next Tuesday from today
  // SKU map by category
  const CAT_SKU = {"5inch":"DC62042","3inch":"DC62041","fused":"DC62043","cascades":"DC62047"};

  // Ship date per DC — Tuesday DCs use exportDate, Wednesday DCs use +1 day
  const getDCShipDate = (dc, baseDate) => {
    const wedDCs = ["PHOENXAZDC"];
    if(wedDCs.includes(dc) && baseDate.length===8){
      const y=parseInt(baseDate.slice(0,4)), m=parseInt(baseDate.slice(4,6))-1, d=parseInt(baseDate.slice(6,8));
      const wed = new Date(y,m,d+1);
      return String(wed.getFullYear())+String(wed.getMonth()+1).padStart(2,'0')+String(wed.getDate()).padStart(2,'0');
    }
    return baseDate;
  };

  const exportAllocation = () => {
    if(typeof window.XLSX !== 'undefined'){
      runExport(window.XLSX);
    } else {
      const existing = document.getElementById('sheetjs-script');
      if(existing){ existing.addEventListener('load', ()=>runExport(window.XLSX)); return; }
      const script = document.createElement('script');
      script.id = 'sheetjs-script';
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
      script.onload = () => runExport(window.XLSX);
      script.onerror = () => alert('Failed to load Excel library. Check your connection.');
      document.head.appendChild(script);
    }
  };

      const runExport = (XLSX) => {
    try {
      const sku = CAT_SKU[allocCategory[0]] || "DC62042";
      const catLabel = allocCategory.map(k=>ALLOC_CATEGORIES.find(c=>c.key===k)?.label||k).join(", ");
      const packSize = {"5inch":10,"3inch":15,"fused":10,"cascades":6}[allocCategory[0]]||10;
      const now = new Date().toLocaleString();
      const wb = XLSX.utils.book_new();

      // Group current allocData by DC — skip 0 rec cases
      const dcGroups = {};
      allocData.forEach(r => {
        if((r.recCases||0) <= 0) return;
        const dc = STORE_META[r.store]?.dc || "UNKNOWN";
        if(!allocDC.includes(dc)) return;
        if(!dcGroups[dc]) dcGroups[dc] = [];
        dcGroups[dc].push(r);
      });

      if(Object.keys(dcGroups).length === 0){
        alert('No stores with Rec. Cases > 0 found for the current filter.');
        return;
      }

      const centerStyle = {alignment:{horizontal:"center",vertical:"center"}};
      const headerStyle = {alignment:{horizontal:"center",vertical:"center"},font:{bold:true}};
      const titleStyle = {alignment:{horizontal:"center",vertical:"center"},font:{bold:true,sz:13}};

      // ── SUMMARY SHEET (first tab) ──────────────────────────────────────────
      const fw = allocFWs.length>0 ? "FW"+String(allocFWs[0]).slice(-2)+"-"+String(allocFWs[allocFWs.length-1]).slice(-2) : "YTD";
      const summaryData = [
        [`Allocation Summary — ${catLabel} — ${fw} — Generated: ${now}`,"","","","",""],
        ["","","","","",""],
        ["DC","Ship Date","Item #","Pack","Total Cases","Stores"],
      ];

      let grandCases = 0, grandStores = 0;
      Object.entries(dcGroups).forEach(([dc, rows]) => {
        const shipDate = getDCShipDate(dc, exportDate);
        const totalCases = rows.reduce((a,r)=>a+(r.recCases||0),0);
        summaryData.push([dc, shipDate, sku, packSize, totalCases, rows.length]);
        grandCases += totalCases;
        grandStores += rows.length;
      });
      summaryData.push(["","","","","",""]);
      summaryData.push(["TOTAL","","","",grandCases,grandStores]);

      const summaryWs = XLSX.utils.aoa_to_sheet(summaryData);
      summaryWs['!cols'] = [{wch:14},{wch:12},{wch:12},{wch:8},{wch:14},{wch:10}];
      summaryWs['!merges'] = [{s:{r:0,c:0},e:{r:0,c:5}}];

      // Style all cells
      const sr = XLSX.utils.decode_range(summaryWs['!ref']);
      for(let R=sr.s.r; R<=sr.e.r; R++){
        for(let C=sr.s.c; C<=sr.e.c; C++){
          const addr = XLSX.utils.encode_cell({r:R,c:C});
          if(!summaryWs[addr]) continue;
          if(R===0) summaryWs[addr].s = titleStyle;
          else if(R===2) summaryWs[addr].s = headerStyle;
          else if(R===summaryData.length-1) summaryWs[addr].s = headerStyle; // TOTAL row
          else summaryWs[addr].s = centerStyle;
        }
      }
      XLSX.utils.book_append_sheet(wb, summaryWs, "Summary");

      // ── DC SHEETS ──────────────────────────────────────────────────────────
      Object.entries(dcGroups).forEach(([dc, rows]) => {
        const shipDate = getDCShipDate(dc, exportDate);
        const sheetData = [
          ["SKU","Store","Qty","DC","Ship Date"],
          ...rows.map(r => [sku, Number(r.store), r.recCases, dc, shipDate])
        ];
        const ws = XLSX.utils.aoa_to_sheet(sheetData);
        ws['!cols'] = [{wch:12},{wch:10},{wch:8},{wch:14},{wch:12}];

        const range = XLSX.utils.decode_range(ws['!ref']);
        for(let R=range.s.r; R<=range.e.r; R++){
          for(let C=range.s.c; C<=range.e.c; C++){
            const addr = XLSX.utils.encode_cell({r:R,c:C});
            if(!ws[addr]) continue;
            ws[addr].s = R===0 ? headerStyle : centerStyle;
          }
        }
        XLSX.utils.book_append_sheet(wb, ws, dc.substring(0,31));
      });

      // ── CORRECTIONS LOG ───────────────────────────────────────────────────
      const corrRows = CORRECTIONS_LOG.filter(r=>allocDC.includes(r.dc));
      if(corrRows.length > 0){
        const corrData = [
          [`Corrections Log — Generated: ${now}`,"","","","","","","",""],
          ["FW","DC","Store","Store Name","Product","Original Cases","Corrected Cases","Difference","Source"],
          ...corrRows.map(r=>["FW"+String(r.fw).slice(-2),r.dc,r.store,STORE_META[r.store]?.name||"",r.product,r.orig,r.corrected,r.diff,r.source||"DC Template"])
        ];
        const corrWs = XLSX.utils.aoa_to_sheet(corrData);
        corrWs['!cols'] = [{wch:6},{wch:12},{wch:8},{wch:28},{wch:22},{wch:14},{wch:14},{wch:10},{wch:16}];
        corrWs['!merges'] = [{s:{r:0,c:0},e:{r:0,c:8}}];
        const cr = XLSX.utils.decode_range(corrWs['!ref']);
        for(let R=cr.s.r; R<=cr.e.r; R++){
          for(let C=cr.s.c; C<=cr.e.c; C++){
            const addr = XLSX.utils.encode_cell({r:R,c:C});
            if(corrWs[addr]) corrWs[addr].s = R<=1 ? headerStyle : centerStyle;
          }
        }
        XLSX.utils.book_append_sheet(wb, corrWs, "Corrections Log");
      }

      const filename = `Allocation_${catLabel.replace(/[^a-zA-Z0-9]/g,'')}_${fw}_${exportDate}.xlsx`;
      XLSX.writeFile(wb, filename, {cellStyles:true});
    } catch(err) {
      alert('Export failed: ' + err.message);
      console.error('Export error:', err);
    }
  };

  const isMobile = typeof window!=="undefined"&&window.innerWidth<640;
  const tabS = active => ({padding:isMobile?"8px 10px":"12px 22px",cursor:"pointer",fontFamily:"'DM Sans',sans-serif",fontSize:isMobile?12:14,letterSpacing:isMobile?0.3:0.8,borderRadius:6,border:"none",background:active?"#c8934a":"transparent",color:active?"#fff":"#3a6a8a",transition:"all 0.15s",whiteSpace:"nowrap",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"});
  const tdS = (align,color) => ({padding:"9px 14px",textAlign:align||"left",fontSize:14,color:color||"#0a0f1e",fontFamily:"'DM Sans',sans-serif",borderBottom:"1px solid #d8d3c9"});

  const dashboard = (
    <div style={{minHeight:"100vh",background:"#f5f4f0",color:"#0a0f1e",fontFamily:"'DM Sans',sans-serif",padding:"0 0 60px 0"}}>
      {/* Header */}
      <div style={{background:"#ffffff",borderBottom:"1px solid #d8d3c9",padding:isMobile?"10px 16px":"14px 28px",display:"flex",alignItems:"center",gap:isMobile?10:20}}>
        <img src={LOGO_B64} alt="Sprouts" style={{height:isMobile?32:44,objectFit:"contain",flexShrink:0}}/>
        <div style={{minWidth:0}}>
          <div style={{fontSize:isMobile?12:16,fontWeight:700,color:"#0a0f1e",letterSpacing:0.2,fontFamily:"'DM Sans',sans-serif"}}>FLORAL SALES DASHBOARD</div>
          <div style={{fontSize:12,color:"#2d3752",letterSpacing:isMobile?1:2,marginTop:2}}>FY2026 vs FY2025</div>
        </div>
        {!isMobile&&<div style={{marginLeft:"auto",fontSize:12,color:"#2d3752",textAlign:"right"}}>
          <div>DATA THRU {FW_LABEL(ALL_FWS[ALL_FWS.length-1])}</div>
          <div style={{marginTop:2}}>{new Date().toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})}</div>
        </div>}
      </div>

      {/* Date Presets */}
      <div style={{background:"#f5f4f0",borderBottom:"1px solid #d8d3c9",padding:"10px 28px",display:tab==="alloc"?"none":"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
        <span style={{fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif",letterSpacing:0.3,marginRight:4}}>DATE RANGE:</span>
        {[["last4","Last 4 Wks"],["last8","Last 8 Wks"],["ytd","Full YTD"],["custom","Custom"]].map(([key,lbl])=>(
          <button key={key} onClick={()=>applyPreset(key)} style={{padding:"5px 14px",background:datePreset===key?"#c8934a":"#ffffff",border:"1px solid "+(datePreset===key?"#c8934a":"#d8d3c9"),color:datePreset===key?"#fff":"#2d3752",borderRadius:6,cursor:"pointer",fontSize:13,fontFamily:"DM Sans,sans-serif",transition:"all 0.15s"}}>{lbl}</button>
        ))}
        {datePreset==="custom"&&(
          <div style={{display:"flex",alignItems:"center",gap:6,marginLeft:4}}>
            <span style={{fontSize:12,color:"#2d3752"}}>FROM</span>
            <select value={customFrom} onChange={e=>{const v=Number(e.target.value);setCustomFrom(v);applyCustom(v,customTo);}} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:13,borderRadius:5,padding:"4px 8px",fontFamily:"DM Sans,sans-serif"}}>
              {ALL_FWS_FULL.map(fw=><option key={fw} value={fw}>{FW_LABEL(fw)}</option>)}
            </select>
            <span style={{fontSize:12,color:"#2d3752"}}>TO</span>
            <select value={customTo} onChange={e=>{const v=Number(e.target.value);setCustomTo(v);applyCustom(customFrom,v);}} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:13,borderRadius:5,padding:"4px 8px",fontFamily:"DM Sans,sans-serif"}}>
              {ALL_FWS_FULL.map(fw=><option key={fw} value={fw}>{FW_LABEL(fw)}</option>)}
            </select>
          </div>
        )}
        <span style={{fontSize:12,color:"#2d3752",marginLeft:8}}>
          {FW_LABEL([...selFW].sort()[0])} – {FW_LABEL([...selFW].sort().slice(-1)[0])} · {selFW.length} {selFW.length===1?"week":"weeks"}
        </span>
      </div>

      {/* Filters */}
      <div style={{background:"#ffffff",borderBottom:"1px solid #d8d3c9",padding:"12px 28px",display:tab==="alloc"?"none":"flex",gap:10,flexWrap:"wrap",alignItems:"center"}}>
        <MultiSelect label="DC" options={ALL_DCS} selected={selDC} onChange={setSelDC}/>
        <MultiSelect label="Product" options={ALL_PRODUCTS_SORTED} selected={selProd} onChange={setSelProd}/>
        <MultiSelect label="Vendor" options={ALL_VENDORS_SORTED} selected={selVendor} onChange={setSelVendor}/>
        <MultiSelect label="Category" options={ALL_CATEGORIES_SORTED} selected={selCategory} onChange={setSelCategory}/>
        <div style={{fontSize:12,color:"#2d3752",marginLeft:"auto",lineHeight:1.6}}>
          <div>ST% = Units Sold / Outbound Pieces</div>
          <div style={{display:"flex",gap:12,marginTop:2}}>
            <span style={{color:"#4ade80"}}>■ ≥80%</span>
            <span style={{color:"#f5a623"}}>■ 60–79%</span>
            <span style={{color:"#f87171"}}>■ &lt;60%</span>
          </div>
        </div>
        <button onClick={()=>{applyPreset("ytd");setCustomFrom(ALL_FWS_FULL[0]);setCustomTo(ALL_FWS_FULL[ALL_FWS_FULL.length-1]);setSelDC([...ALL_DCS]);setSelProd(ALL_PRODUCTS.filter(p=>!['LAVENDER-BUNCH-DRIED','LAVENDER-SACHET'].includes(p)));setSelVendor(ALL_VENDORS.filter(v=>!['CYMA','LAVENDER'].includes(v)));setSelCategory(ALL_CATEGORIES.filter(c=>c!=='Lavender'));setExpandedDC(null);setStoreWkFilter([ALL_FWS_FULL[ALL_FWS_FULL.length-1]]);setStoreDCFilter([...ALL_DCS]);}} style={{padding:"7px 14px",background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",borderRadius:6,cursor:"pointer",fontSize:13,fontFamily:"DM Sans,sans-serif",letterSpacing:0.2}}>RESET</button>
      </div>

      {/* Tabs */}
      <div style={{padding:isMobile?"8px 12px 0":"16px 28px 0",display:"flex",gap:isMobile?4:8,borderBottom:"1px solid #d8d3c9",background:"#f5f4f0",overflowX:"auto",WebkitOverflowScrolling:"touch",scrollbarWidth:"none"}}>
        <button style={tabS(tab==="wow")} onClick={()=>setTab("wow")}>WoW</button>
        <button style={tabS(tab==="yoy")} onClick={()=>setTab("yoy")}>YoY</button>
        <button style={tabS(tab==="ytd")} onClick={()=>setTab("ytd")}>YTD Summary</button>
        <button style={tabS(tab==="trend")} onClick={()=>setTab("trend")}>Trend Chart</button>
        <button style={tabS(tab==="stores")} onClick={()=>setTab("stores")}>Store Analytics</button>
        <button style={tabS(tab==="district")} onClick={()=>setTab("district")}>Districts</button>
        <button style={{...tabS(tab==="alloc"),background:tab==="alloc"?"#7c3aed":"transparent",border:tab==="alloc"?"1px solid #7c3aed":"1px solid transparent"}} onClick={()=>setTab("alloc")}>Allocations</button>
      </div>

      <div style={{padding:isMobile?"12px 12px":"24px 28px"}}>
      {tab==="wow"&&(
        <div>
          <div style={{fontSize:13,color:"#2d3752",marginBottom:16}}>
            Showing <span style={{color:"#c8934a"}}>{FW_LABEL(latestFW)}</span> vs prev week <span style={{color:"#c8934a"}}>{prevFW?FW_LABEL(prevFW):"—"}</span>
          </div>

          {/* WoW KPI Row */}
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:20}}>
            <KPI label={"This Wk ("+FW_LABEL(latestFW)+")"} value={fmt$(thisS)}/>
            <KPI label={prevFW?"Last Wk ("+FW_LABEL(prevFW)+")":"Last Week"} value={fmt$(lastS)}/>
            <KPI label="WoW $" value={fmtD(wowD)} delta={wowD} pct={wowP}/>
            <KPI label="WoW %" value={wowP!=null?fmtP(wowP):"—"} delta={wowP} pct={null}/>
          </div>

          {/* WoW ST KPI Row */}
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:28}}>
            <KPI label={"ST% This Wk"} value={fmtST(thisST)} stVal={thisST}/>
            <KPI label={"ST% Last Wk"} value={fmtST(lastST)} stVal={lastST}/>
            <KPI label={"ST% WoW Chg"} value={stDelta!=null?fmtP(stDelta):"—"} delta={stDelta} pct={null}/>
          </div>

          {/* TopBottom3 hidden */}

          <div style={{display:"grid",gridTemplateColumns:"1fr",gap:20}}>
            {/* By Product - WoW */}
            <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
              <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>By Product · {FW_LABEL(latestFW)}</span>
                <select value={sortWow} onChange={e=>setSortWow(e.target.value)} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:12,borderRadius:4,padding:"3px 6px",fontFamily:"'DM Sans',sans-serif",cursor:"pointer"}}>
                  <option value="sales">Sort: Sales</option>
                  <option value="wd">Sort: WoW $</option>
                  <option value="wp">Sort: WoW %</option>
                  <option value="st">Sort: ST%</option>
                </select>
              </div>
              <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <THead cols={[{key:"prod",label:"Product"},{key:"sales",label:"This Wk $",num:true},{key:"units",label:"Units",num:true},{key:"aur",label:"AUR",num:true},{key:"wd",label:"WoW $",num:true},{key:"wp",label:"WoW %",num:true},{key:"st",label:"ST%",num:true},{key:"spark",label:"Trend FW01→FW12",num:true}]} sort={sortWow} onSort={setSortWow}/>
                <tbody>
                  {prodTable.map((r,i)=>(
                    <tr key={r.prod} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                      <td style={tdS()}>{r.prod}</td>
                      <td style={tdS("right")}>{fmt$(r.sales)}</td>
                      <td style={tdS("right")}>{fmtU(r.units)}</td>
                      <td style={tdS("right")}>{r.aur!=null?"$"+r.aur.toFixed(2):"—"}</td>
                      <td style={tdS("right",clr(r.wd))}>{r.wd!=null?fmtD(r.wd):"—"}</td>
                      <td style={tdS("right",clr(r.wp))}>{r.wp!=null?fmtP(r.wp):"—"}</td>
                      <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}><STBar val={r.st}/></td>
                      <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9",textAlign:"right"}}><Sparkline prod={r.prod}/></td>
                    </tr>
                  ))}
                </tbody>
              </table>
              </div>
            </div>

            {/* By DC - WoW */}
            <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
              <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9"}}>
                <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>By DC · {FW_LABEL(latestFW)}</span>
              </div>
              <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <THead cols={[{key:"dc",label:"DC"},{key:"sales",label:"This Wk $",num:true},{key:"units",label:"Units",num:true},{key:"aur",label:"AUR",num:true},{key:"wd",label:"WoW $",num:true},{key:"wp",label:"WoW %",num:true},{key:"st",label:"ST%",num:true}]} sort="sales"/>
                <tbody>
                  {dcTable.map((r,i)=>{
                    const isExp = expandedDC===r.dc;
                    return [
                      <tr key={r.dc} onClick={()=>setExpandedDC(isExp?null:r.dc)} style={{background:i%2===0?"#ffffff":"#f5f4f0",cursor:"pointer"}}>
                        <td style={tdS()}><span style={{color:"#c8934a",marginRight:6,fontSize:12}}>{isExp?"▼":"▶"}</span>{r.dc}</td>
                        <td style={tdS("right")}>{fmt$(r.sales)}</td>
                        <td style={tdS("right")}>{fmtU(r.units)}</td>
                        <td style={tdS("right")}>{r.aur!=null?"$"+r.aur.toFixed(2):"—"}</td>
                        <td style={tdS("right",clr(r.wd))}>{r.wd!=null?fmtD(r.wd):"—"}</td>
                        <td style={tdS("right",clr(r.wp))}>{r.wp!=null?fmtP(r.wp):"—"}</td>
                        <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}><STBar val={r.st}/></td>
                      </tr>,
                      isExp && storeTable.map((s,j)=>(
                        <tr key={r.dc+"-"+s.store} style={{background:"#f5f4f0"}}>
                          <td style={{...tdS(),paddingLeft:28,color:"#2d3752",fontSize:13}}>Store {s.store}</td>
                          <td style={tdS("right")}>{fmt$(s.sales)}</td>
                          <td style={tdS("right")}>{fmtU(s.units)}</td>
                          <td style={tdS("right")}>{s.units>0?"$"+(s.sales/s.units).toFixed(2):"—"}</td>
                          <td style={tdS("right",clr(s.wd))}>{s.wd!=null?fmtD(s.wd):"—"}</td>
                          <td style={tdS("right",clr(s.wp))}>{s.wp!=null?fmtP(s.wp):"—"}</td>
                          <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}></td>
                        </tr>
                      ))
                    ];
                  })}
                </tbody>
              </table>
              </div>
            </div>
          </div>
        </div>
      )}

      {tab==="yoy"&&(
        <div>
          <div style={{fontSize:13,color:"#2d3752",marginBottom:16}}>
            Showing <span style={{color:"#c8934a"}}>{FW_LABEL(latestFW)}</span> vs same week last year <span style={{color:"#c8934a"}}>{lyFW?"FW"+String(lyFW).slice(-2)+" FY25":"—"}</span>
          </div>

          {/* YoY KPI Row */}
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:20}}>
            <KPI label={"This Wk ("+FW_LABEL(latestFW)+")"} value={fmt$(thisS)}/>
            <KPI label="Same Wk LY" value={fmt$(lyS)}/>
            <KPI label="YoY $" value={fmtD(yoyD)} delta={yoyD} pct={yoyP}/>
            <KPI label="YoY %" value={yoyP!=null?fmtP(yoyP):"—"} delta={yoyP} pct={null}/>
          </div>

          {/* YoY ST KPI Row */}
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:28}}>
            <KPI label={"ST% This Wk"} value={fmtST(thisST)} stVal={thisST}/>
            <KPI label={"ST% Same Wk LY"} value={fmtST(lyST)} stVal={lyST}/>
            <KPI label={"ST% YoY Chg"} value={(thisST!=null&&lyST!=null)?fmtP(thisST-lyST):"—"} delta={thisST!=null&&lyST!=null?thisST-lyST:null} pct={null}/>
          </div>

          {/* TopBottom3 hidden */}

          <div style={{display:"grid",gridTemplateColumns:"1fr",gap:20}}>
            {/* By Product - YoY */}
            <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
              <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>By Product · YoY</span>
                <select value={sortWow} onChange={e=>setSortWow(e.target.value)} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:12,borderRadius:4,padding:"3px 6px",fontFamily:"'DM Sans',sans-serif",cursor:"pointer"}}>
                  <option value="sales">Sort: Sales</option>
                  <option value="yd">Sort: YoY $</option>
                  <option value="yp">Sort: YoY %</option>
                  <option value="st">Sort: ST%</option>
                </select>
              </div>
              <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <THead cols={[{key:"prod",label:"Product"},{key:"sales",label:"FY26 $",num:true},{key:"units",label:"Units",num:true},{key:"aur",label:"AUR",num:true},{key:"lyS",label:"FY25 $",num:true},{key:"yd",label:"YoY $",num:true},{key:"yp",label:"YoY %",num:true},{key:"st",label:"ST% FY26",num:true},{key:"spark",label:"Trend",num:true}]} sort={sortWow} onSort={setSortWow}/>
                <tbody>
                  {prodTable.map((r,i)=>(
                    <tr key={r.prod} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                      <td style={tdS()}>{r.prod}</td>
                      <td style={tdS("right")}>{fmt$(r.sales)}</td>
                      <td style={tdS("right")}>{fmtU(r.units)}</td>
                      <td style={tdS("right")}>{r.aur!=null?"$"+r.aur.toFixed(2):"—"}</td>
                      <td style={tdS("right")}>{fmt$(r.lyS)}</td>
                      <td style={tdS("right",clr(r.yd))}>{r.yd!=null?fmtD(r.yd):"—"}</td>
                      <td style={tdS("right",clr(r.yp))}>{r.yp!=null?fmtP(r.yp):"—"}</td>
                      <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}><STBar val={r.st}/></td>
                      <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9",textAlign:"right"}}><Sparkline prod={r.prod}/></td>
                    </tr>
                  ))}
                </tbody>
              </table>
              </div>
            </div>

            {/* By DC - YoY */}
            <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
              <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9"}}>
                <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>By DC · YoY</span>
              </div>
              <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <THead cols={[{key:"dc",label:"DC"},{key:"sales",label:"FY26 $",num:true},{key:"units",label:"Units",num:true},{key:"aur",label:"AUR",num:true},{key:"lyS",label:"FY25 $",num:true},{key:"yd",label:"YoY $",num:true},{key:"yp",label:"YoY %",num:true},{key:"st",label:"ST% FY26",num:true}]} sort="sales"/>
                <tbody>
                  {dcTable.map((r,i)=>{
                    const isExp = expandedDC===r.dc;
                    return [
                      <tr key={r.dc} onClick={()=>setExpandedDC(isExp?null:r.dc)} style={{background:i%2===0?"#ffffff":"#f5f4f0",cursor:"pointer"}}>
                        <td style={tdS()}><span style={{color:"#c8934a",marginRight:6,fontSize:12}}>{isExp?"▼":"▶"}</span>{r.dc}</td>
                        <td style={tdS("right")}>{fmt$(r.sales)}</td>
                        <td style={tdS("right")}>{fmtU(r.units)}</td>
                        <td style={tdS("right")}>{r.aur!=null?"$"+r.aur.toFixed(2):"—"}</td>
                        <td style={tdS("right")}>{fmt$(r.lyS)}</td>
                        <td style={tdS("right",clr(r.yd))}>{r.yd!=null?fmtD(r.yd):"—"}</td>
                        <td style={tdS("right",clr(r.yp))}>{r.yp!=null?fmtP(r.yp):"—"}</td>
                        <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}><STBar val={r.st}/></td>
                      </tr>,
                      isExp && storeTable.map((s,j)=>(
                        <tr key={r.dc+"-s-"+s.store} style={{background:"#f5f4f0"}}>
                          <td style={{...tdS(),paddingLeft:28,color:"#2d3752",fontSize:13}}>Store {s.store}</td>
                          <td style={tdS("right")}>{fmt$(s.sales)}</td>
                          <td style={tdS("right")}>{fmtU(s.units)}</td>
                          <td style={tdS("right")}>{s.units>0?"$"+(s.sales/s.units).toFixed(2):"—"}</td>
                          <td style={tdS("right")} colSpan={4}></td>
                        </tr>
                      ))
                    ];
                  })}
                </tbody>
              </table>
              </div>
            </div>
          </div>
        </div>
      )}

      {tab==="ytd"&&(
        <div>
          <div style={{fontSize:13,color:"#2d3752",marginBottom:16}}>
            YTD: <span style={{color:"#c8934a"}}>{selFWSorted.length>0?FW_LABEL(selFWSorted[0])+" – "+FW_LABEL(selFWSorted[selFWSorted.length-1]):"—"}</span>
          </div>

          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:20}}>
            <KPI label="FY26 YTD Sales" value={fmt$(ytd26)}/>
            <KPI label="FY25 YTD Sales" value={fmt$(ytd25)}/>
            <KPI label="YTD Δ $" value={fmtD(ytdD)} delta={ytdD} pct={ytdP}/>
            <KPI label="YTD Δ %" value={ytdP!=null?fmtP(ytdP):"—"} delta={ytdP} pct={null}/>
          </div>
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:28}}>
            <KPI label="FY26 YTD ST%" value={fmtST(ytdST26)} stVal={ytdST26}/>
            <KPI label="FY25 YTD ST%" value={fmtST(ytdST25)} stVal={ytdST25}/>
            <KPI label="ST% YoY Δ" value={(ytdST26!=null&&ytdST25!=null)?fmtP(ytdST26-ytdST25):"—"} delta={ytdST26!=null&&ytdST25!=null?ytdST26-ytdST25:null} pct={null}/>
          </div>

          {/* TopBottom3 hidden */}

          <div style={{display:"grid",gridTemplateColumns:"1fr",gap:20}}>
            {/* YTD by DC */}
            <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
              <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>YTD by DC</span>
                <select value={sortYTDDC} onChange={e=>setSortYTDDC(e.target.value)} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:12,borderRadius:4,padding:"3px 6px",fontFamily:"'DM Sans',sans-serif",cursor:"pointer"}}>
                  <option value="s26">Sort: FY26 $</option>
                  <option value="delta">Sort: Δ $</option>
                  <option value="pct">Sort: Δ %</option>
                  <option value="st26">Sort: ST%</option>
                </select>
              </div>
              <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <THead cols={[{key:"dc",label:"DC"},{key:"s26",label:"FY26 $",num:true},{key:"u26",label:"Units",num:true},{key:"aur26",label:"AUR",num:true},{key:"s25",label:"FY25 $",num:true},{key:"delta",label:"Δ $",num:true},{key:"pct",label:"Δ %",num:true},{key:"st26",label:"ST% FY26",num:true}]} sort={sortYTDDC} onSort={setSortYTDDC}/>
                <tbody>
                  {ytdByDC.map((r,i)=>(
                    <tr key={r.dc} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                      <td style={tdS()}>{r.dc}</td>
                      <td style={tdS("right")}>{fmt$(r.s26)}</td>
                      <td style={tdS("right")}>{fmtU(r.u26)}</td>
                      <td style={tdS("right")}>{r.aur26!=null?"$"+r.aur26.toFixed(2):"—"}</td>
                      <td style={tdS("right")}>{fmt$(r.s25)}</td>
                      <td style={tdS("right",clr(r.delta))}>{fmtD(r.delta)}</td>
                      <td style={tdS("right",clr(r.pct))}>{r.pct!=null?fmtP(r.pct):"—"}</td>
                      <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}><STBar val={r.st26}/></td>
                    </tr>
                  ))}
                </tbody>
              </table>
              </div>
            </div>

            {/* YTD by Product */}
            <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
              <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>YTD by Product</span>
                <select value={sortYTDProd} onChange={e=>setSortYTDProd(e.target.value)} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:12,borderRadius:4,padding:"3px 6px",fontFamily:"'DM Sans',sans-serif",cursor:"pointer"}}>
                  <option value="s26">Sort: FY26 $</option>
                  <option value="delta">Sort: Δ $</option>
                  <option value="pct">Sort: Δ %</option>
                  <option value="st26">Sort: ST%</option>
                </select>
              </div>
              <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <THead cols={[{key:"prod",label:"Product"},{key:"s26",label:"FY26 $",num:true},{key:"u26",label:"Units",num:true},{key:"aur26",label:"AUR",num:true},{key:"s25",label:"FY25 $",num:true},{key:"delta",label:"Δ $",num:true},{key:"pct",label:"Δ %",num:true},{key:"st26",label:"ST% FY26",num:true},{key:"spark",label:"Trend",num:true}]} sort={sortYTDProd} onSort={setSortYTDProd}/>
                <tbody>
                  {ytdByProd.map((r,i)=>(
                    <tr key={r.prod} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                      <td style={tdS()}>{r.prod}</td>
                      <td style={tdS("right")}>{fmt$(r.s26)}</td>
                      <td style={tdS("right")}>{fmtU(r.u26)}</td>
                      <td style={tdS("right")}>{r.aur26!=null?"$"+r.aur26.toFixed(2):"—"}</td>
                      <td style={tdS("right")}>{fmt$(r.s25)}</td>
                      <td style={tdS("right",clr(r.delta))}>{fmtD(r.delta)}</td>
                      <td style={tdS("right",clr(r.pct))}>{r.pct!=null?fmtP(r.pct):"—"}</td>
                      <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}><STBar val={r.st26}/></td>
                      <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9",textAlign:"right"}}><Sparkline prod={r.prod}/></td>
                    </tr>
                  ))}
                </tbody>
              </table>
              </div>
            </div>
          </div>
        </div>
      )}

      {tab==="trend"&&(
        <div>
          {/* Controls */}
          <div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap",marginBottom:20}}>
            <div style={{fontSize:13,color:"#2d3752"}}>METRIC:</div>
            {[["sales","Gross Sales"],["units","Units"]].map(([k,l])=>(
              <button key={k} onClick={()=>setTrendMetric(k)} style={{padding:"5px 14px",background:trendMetric===k?"#c8934a":"#ffffff",border:"1px solid "+(trendMetric===k?"#c8934a":"#d83a5a"),color:trendMetric===k?"#fff":"#5a8aaa",borderRadius:6,cursor:"pointer",fontSize:13,fontFamily:"DM Sans,sans-serif"}}>{l}</button>
            ))}
            <div style={{marginLeft:16,fontSize:13,color:"#2d3752"}}>VIEW:</div>
            {[["yoy","FY26 vs FY25"],["total","Total"],["bydc","By DC"]].map(([k,l])=>(
              <button key={k} onClick={()=>setTrendView(k)} style={{padding:"5px 14px",background:trendView===k?"#1a7a4e":"#ffffff",border:"1px solid "+(trendView===k?"#1a7a4e":"#d8d3c9"),color:trendView===k?"#2aff90":"#5a8aaa",borderRadius:6,cursor:"pointer",fontSize:13,fontFamily:"DM Sans,sans-serif"}}>{l}</button>
            ))}
          </div>

          {/* SVG Line Chart */}
          {(()=>{
            const W=900,H=340,PL=68,PR=20,PT=20,PB=48;
            const cW=W-PL-PR, cH=H-PT-PB;
            const metric = trendMetric==="sales" ? "s26" : "u26";
            const metric25 = trendMetric==="sales" ? "s25" : "u25";
            const fmtVal = v => trendMetric==="sales" ? ("$"+Math.round(v/1000)+"k") : Math.round(v).toLocaleString();
            const fmtTip = v => trendMetric==="sales" ? fmt$(v) : fmtU(v);

            // build series
            const DC_COLORS={"PHOENXAZDC":"#3a8fd4","DALLASTXDC":"#f5a623","FULRTNCADC":"#4ade80","ORLNDOFLDC":"#e879f9","DENVERCODC":"#60d9fa","TRACYCADC":"#fb923c","FOURSEASON":"#a78bfa"};
            let series=[];
            if(trendView==="total"){
              series=[{label:"FY26",color:"#c8934a",vals:trendData.map(d=>trendMetric==="sales"?d.s26:d.u26),dash:false}];
            } else if(trendView==="yoy"){
              series=[
                {label:"FY26",color:"#c8934a",vals:trendData.map(d=>d[metric]),dash:false},
                {label:"FY25",color:"#f5a623",vals:trendData.map(d=>d[metric25]),dash:true}
              ];
            } else {
              series=ALL_DCS.filter(dc=>selDC.includes(dc)).map(dc=>({
                label:dc,color:DC_COLORS[dc]||"#c8934a",
                vals:trendData.map(d=>trendMetric==="sales"?(d.byDC[dc]?.s||0):(d.byDC[dc]?.u||0)),
                dash:false
              }));
            }

            const allVals=series.flatMap(s=>s.vals);
            const maxV=Math.max(...allVals,1);
            const minV=0;
            const xStep=cW/(trendData.length-1);
            const yScale=v=>(cH-((v-minV)/(maxV-minV))*cH);

            const pts = s => trendData.map((d,i)=>[PL+i*xStep, PT+yScale(s.vals[i])]);
            const toPath = points => points.map((p,i)=>(i===0?"M":"L")+p[0].toFixed(1)+","+p[1].toFixed(1)).join(" ");

            // Y-axis ticks
            const yTicks=5;
            const yTickVals=Array.from({length:yTicks+1},(_,i)=>minV+(maxV-minV)*i/yTicks);

            return (
              <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,padding:"20px 24px",marginBottom:20}}>
                <div style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase",marginBottom:12}}>
                  {trendMetric==="sales"?"Gross Sales":"Units"} — Weekly Trend {trendView==="bydc"?"by DC":trendView==="yoy"?"FY26 vs FY25":"All"}
                </div>
                <svg viewBox={"0 0 "+W+" "+H} style={{width:"100%",display:"block"}}>
                  {/* Grid lines */}
                  {yTickVals.map((v,i)=>{
                    const y=PT+yScale(v);
                    return [
                      <line key={"gl"+i} x1={PL} y1={y} x2={W-PR} y2={y} stroke="#d8d3c9" strokeWidth="1"/>,
                      <text key={"yl"+i} x={PL-6} y={y+4} textAnchor="end" fontSize="9" fill="#3a6a8a" fontFamily="DM Sans,sans-serif">{fmtVal(v)}</text>
                    ];
                  })}
                  {/* X labels */}
                  {trendData.map((d,i)=>(
                    <text key={"xl"+i} x={PL+i*xStep} y={H-PT+4} textAnchor="middle" fontSize="9" fill="#3a6a8a" fontFamily="DM Sans,sans-serif">{d.label}</text>
                  ))}
                  {/* Series lines + dots */}
                  {series.map((s,si)=>{
                    const points=pts(s);
                    return [
                      <path key={"path"+si} d={toPath(points)} fill="none" stroke={s.color} strokeWidth="2.5" strokeDasharray={s.dash?"6,4":"none"} opacity="0.9"/>,
                      ...points.map((p,i)=>(
                        <circle key={"dot"+si+"-"+i} cx={p[0]} cy={p[1]} r="4" fill={s.color} stroke="#ffffff" strokeWidth="1.5">
                          <title>{s.label+" "+trendData[i].label+": "+fmtTip(s.vals[i])}</title>
                        </circle>
                      ))
                    ];
                  })}
                  {/* Axis */}
                  <line x1={PL} y1={PT} x2={PL} y2={H-PB} stroke="#d8d3c9" strokeWidth="1"/>
                  <line x1={PL} y1={H-PB} x2={W-PR} y2={H-PB} stroke="#d8d3c9" strokeWidth="1"/>
                </svg>
                {/* Legend */}
                <div style={{display:"flex",gap:16,flexWrap:"wrap",marginTop:12,justifyContent:"center"}}>
                  {series.map(s=>(
                    <div key={s.label} style={{display:"flex",alignItems:"center",gap:6}}>
                      <div style={{width:24,height:3,background:s.color,borderRadius:2,borderTop:s.dash?"2px dashed "+s.color:"none",opacity:0.9}}/>
                      <span style={{fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{s.label}</span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })()}

          {/* Weekly data table beneath chart */}
          <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
            <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9"}}>
              <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>Weekly Detail · FY26 vs FY25</span>
            </div>
            <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <THead cols={[{key:"fw",label:"Week"},{key:"s26",label:"FY26 Sales",num:true},{key:"u26",label:"FY26 Units",num:true},{key:"s25",label:"FY25 Sales",num:true},{key:"u25",label:"FY25 Units",num:true},{key:"delta",label:"YoY $",num:true},{key:"pct",label:"YoY %",num:true}]}/>
              <tbody>
                {trendData.map((d,i)=>{
                  const delta=d.s26-d.s25, pct=d.s25>0?delta/d.s25*100:null;
                  return (
                    <tr key={d.fw} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                      <td style={tdS()}>{d.label}</td>
                      <td style={tdS("right")}>{fmt$(d.s26)}</td>
                      <td style={tdS("right")}>{fmtU(d.u26)}</td>
                      <td style={tdS("right","")}>{fmt$(d.s25)}</td>
                      <td style={tdS("right","")}>{fmtU(d.u25)}</td>
                      <td style={tdS("right",clr(delta))}>{fmtD(delta)}</td>
                      <td style={tdS("right",clr(pct))}>{pct!=null?fmtP(pct):"—"}</td>
                    </tr>
                  );
                })}
                {(()=>{
                  const totS26=trendData.reduce((a,d)=>a+d.s26,0);
                  const totU26=trendData.reduce((a,d)=>a+d.u26,0);
                  const totS25=trendData.reduce((a,d)=>a+d.s25,0);
                  const totU25=trendData.reduce((a,d)=>a+d.u25,0);
                  const totD=totS26-totS25, totP=totS25>0?totD/totS25*100:null;
                  return (
                    <tr style={{background:"#ede9e3",borderTop:"2px solid #c8934a"}}>
                      <td style={{...tdS(),fontWeight:700,color:"#0a0f1e",letterSpacing:0.2,fontSize:13}}>TOTAL</td>
                      <td style={{...tdS("right"),fontWeight:700,color:"#0a0f1e"}}>{fmt$(totS26)}</td>
                      <td style={{...tdS("right"),fontWeight:700,color:"#0a0f1e"}}>{fmtU(totU26)}</td>
                      <td style={{...tdS("right"),fontWeight:700,color:"#0a0f1e"}}>{fmt$(totS25)}</td>
                      <td style={{...tdS("right"),fontWeight:700,color:"#0a0f1e"}}>{fmtU(totU25)}</td>
                      <td style={{...tdS("right",clr(totD)),fontWeight:700}}>{fmtD(totD)}</td>
                      <td style={{...tdS("right",clr(totP)),fontWeight:700}}>{totP!=null?fmtP(totP):"—"}</td>
                    </tr>
                  );
                })()}
              </tbody>
            </table>
            </div>
          </div>
        </div>
      )}

      {tab==="stores"&&(
        <div>
          {/* Store controls */}
          <div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap",marginBottom:20}}>
            <MultiSelect label="Week" options={ALL_FWS_FULL} selected={storeWkFilter} onChange={setStoreWkFilter} fmtOpt={FW_LABEL}/>
            <MultiSelect label="DC" options={ALL_DCS} selected={storeDCFilter} onChange={setStoreDCFilter}/>
            <div style={{marginLeft:8,fontSize:13,color:"#2d3752"}}>SEARCH:</div>
            <input value={storeSearch} onChange={e=>setStoreSearch(e.target.value)} placeholder="Store # or DC..." style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:13,borderRadius:5,padding:"5px 10px",fontFamily:"DM Sans,sans-serif",width:160,outline:"none"}}/>
            {storeSearch&&<button onClick={()=>setStoreSearch("")} style={{background:"transparent",border:"none",color:"#2d3752",cursor:"pointer",fontSize:15,padding:"2px 6px"}}>✕</button>}
            <div style={{marginLeft:"auto",fontSize:12,color:"#2d3752"}}>{storeAnalytics.length} stores shown</div>
          </div>

          {/^\d+$/.test(storeSearch)&&storeSearch&&(()=>{
            const storeNum = storeSearch;
            const cats = [['5inch','5" Orchid'],['3inch','3" Orchid'],['fused','5" Fused'],['cascades','Cascades']];
            const hasSomeData = cats.some(([k])=>STORE_OUTBOUND[k]?.[storeNum]);
            if (!hasSomeData) return null;
            const maxIntensity = cats.reduce((mx,[k])=>{
              const sd=STORE_OUTBOUND[k]?.[storeNum]||{};
              return Object.values(sd).reduce((m,v)=>Math.max(m,v[0]),mx);
            },0);
            return (
              <div style={{background:'#ffffff',border:'1px solid #d8d3c9',borderRadius:10,overflow:'hidden',marginTop:20}}>
                <div style={{padding:'6px 16px',background:'#ede9e3',borderBottom:'1px solid #d8d3c9',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                  <span style={{fontSize:13,color:'#7c3aed',letterSpacing:0.5,textTransform:'uppercase',fontFamily:'DM Sans,sans-serif',fontWeight:600}}>Cases Received by Category · Store {storeSearch}</span>
                </div>
                <div style={{overflowX:'auto'}}>
                <table style={{width:'100%',borderCollapse:'separate',borderSpacing:0,minWidth:600}}>
                  <thead>
                    <tr style={{background:'#ede9e3'}}>
                      <th style={{padding:'5px 14px',textAlign:'left',fontSize:12,color:'#2d3752',letterSpacing:0.3,textTransform:'uppercase',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif',fontWeight:500,minWidth:100,position:'sticky',left:0,background:'#ede9e3',zIndex:2}}>Category</th>
                      {ALL_FWS.map(fw=>(
                        <th key={fw} style={{padding:'5px 10px',textAlign:'center',fontSize:11,color:'#2d3752',letterSpacing:0.3,textTransform:'uppercase',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif',fontWeight:500,minWidth:48}}>{FW_LABEL(fw)}</th>
                      ))}
                      <th style={{padding:'5px 14px',textAlign:'right',fontSize:12,color:'#7c3aed',letterSpacing:0.3,textTransform:'uppercase',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif',fontWeight:600}}>Total</th>
                    </tr>
                  </thead>
                  <tbody>
                    {cats.map(([catKey,catLabel],ri)=>{
                      const sd = STORE_OUTBOUND[catKey]?.[storeNum]||{};
                      const total = Object.values(sd).reduce((a,v)=>a+v[0],0);
                      if (total===0) return null;
                      return (
                        <tr key={catKey} style={{background:ri%2===0?'#ffffff':'#f5f4f0'}}>
                          <td style={{padding:'5px 14px',fontSize:13,color:'#0a0f1e',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif',whiteSpace:'nowrap',position:'sticky',left:0,background:'inherit',zIndex:1}}>{catLabel}</td>
                          {ALL_FWS.map(fw=>{
                            const v = sd[String(fw)];
                            const cases = v?v[0]:0;
                            const intensity = maxIntensity>0?cases/maxIntensity:0;
                            const bg = cases>0?`rgba(124,58,237,${0.15+intensity*0.6})`:'transparent';
                            return (
                              <td key={fw} style={{padding:'5px 10px',textAlign:'center',fontSize:12,fontWeight:cases>0?700:400,color:cases>0?'#3b1f8c':'#9aa3bd',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif',background:bg}}>
                                {cases>0?cases:'—'}
                              </td>
                            );
                          })}
                          <td style={{padding:'5px 14px',textAlign:'right',fontSize:13,fontWeight:700,color:'#7c3aed',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif'}}>{total}</td>
                        </tr>
                      );
                    })}
                    <tr style={{background:'#ede9e3'}}>
                      <td style={{padding:'5px 14px',fontSize:13,fontWeight:700,color:'#0a0f1e',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif',position:'sticky',left:0,background:'#ede9e3',zIndex:1}}>TOTAL</td>
                      {ALL_FWS.map(fw=>{
                        const tot = cats.reduce((a,[k])=>{
                          const v=STORE_OUTBOUND[k]?.[storeNum]?.[String(fw)];
                          return a+(v?v[0]:0);
                        },0);
                        return <td key={fw} style={{padding:'5px 10px',textAlign:'center',fontSize:12,fontWeight:700,color:tot>0?'#0a0f1e':'#9aa3bd',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif'}}>{tot>0?tot:'—'}</td>;
                      })}
                      <td style={{padding:'5px 14px',textAlign:'right',fontSize:13,fontWeight:700,color:'#7c3aed',borderBottom:'1px solid #d8d3c9',fontFamily:'DM Sans,sans-serif'}}>
                        {cats.reduce((a,[k])=>a+Object.values(STORE_OUTBOUND[k]?.[storeNum]||{}).reduce((b,v)=>b+v[0],0),0)}
                      </td>
                    </tr>
                  </tbody>
                </table>
                </div>
              </div>
            );
          })()}

          {/* Store KPIs */}
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:20}}>
            <KPI label={"Stores Active"} value={storeAnalytics.length.toString()}/>
            <KPI label="Total Sales" value={fmt$(storeAnalytics.reduce((a,r)=>a+r.sales,0))}/>
            <KPI label="Total Units" value={fmtU(storeAnalytics.reduce((a,r)=>a+r.units,0))}/>
            <KPI label="Avg Sales / Store" value={storeAnalytics.length>0?fmt$(storeAnalytics.reduce((a,r)=>a+r.sales,0)/storeAnalytics.length):"—"}/>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"2fr 1fr",gap:20,marginBottom:20}}>
            {/* WoW Store Table */}
            <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
              <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>Store Detail · {storeWkFilter.length===1?FW_LABEL(storeWkFilter[0]):storeWkFilter.length+" Wks"} vs Prev Wk</span>
                <select value={storeSortKey} onChange={e=>setStoreSortKey(e.target.value)} style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:12,borderRadius:4,padding:"3px 6px",fontFamily:"'DM Sans',sans-serif",cursor:"pointer"}}>
                  <option value="sales">Sort: Sales</option>
                  <option value="units">Sort: Units</option>
                  <option value="wd">Sort: WoW $</option>
                  <option value="wp">Sort: WoW %</option>
                  <option value="aur">Sort: AUR</option>
                </select>
              </div>
              <div style={{overflowX:"auto",maxHeight:520,overflowY:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <THead cols={[{key:"store",label:"Store"},{key:"dc",label:"DC"},{key:"sales",label:"Sales $",num:true},{key:"units",label:"Units",num:true},{key:"aur",label:"AUR",num:true},{key:"wd",label:"WoW $",num:true},{key:"wp",label:"WoW %",num:true}]} sort={storeSortKey} onSort={setStoreSortKey}/>
                <tbody>
                  {storeAnalytics.map((r,i)=>(
                    <tr key={r.dc+"-"+r.store} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                      <td style={tdS()}>
                        <div style={{fontWeight:600}}>{"#"+r.store}</div>
                        <div style={{fontSize:12,color:"#2d3752",marginTop:2}}>{STORE_META[r.store]?.name||""}</div>
                      </td>
                      <td style={tdS("left","#5a8aaa")}>{r.dc.replace("DC","").replace("CADC","").replace("TXDC","").replace("CODC","").replace("FLDC","").replace("AZDC","")}</td>
                      <td style={tdS("right")}>{fmt$(r.sales)}</td>
                      <td style={tdS("right")}>{fmtU(r.units)}</td>
                      <td style={tdS("right")}>{r.aur!=null?"$"+r.aur.toFixed(2):"—"}</td>
                      <td style={tdS("right",clr(r.wd))}>{r.wd!=null?fmtD(r.wd):"—"}</td>
                      <td style={tdS("right",clr(r.wp))}>{r.wp!=null?fmtP(r.wp):"—"}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              </div>
            </div>

            {/* DC Sales Bar Chart */}
            {(()=>{
              const dcTotals={};
              storeAnalytics.forEach(r=>{dcTotals[r.dc]=(dcTotals[r.dc]||0)+r.sales;});
              const sorted=Object.entries(dcTotals).sort((a,b)=>b[1]-a[1]);
              const maxDC=Math.max(...Object.values(dcTotals),1);
              const DC_COLORS={"PHOENXAZDC":"#3a8fd4","DALLASTXDC":"#f5a623","FULRTNCADC":"#4ade80","ORLNDOFLDC":"#e879f9","DENVERCODC":"#60d9fa","TRACYCADC":"#fb923c","FOURSEASON":"#a78bfa"};
              return (
                <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,padding:"20px"}}>
                  <div style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase",marginBottom:16}}>Sales by DC · {storeWkFilter.length===1?FW_LABEL(storeWkFilter[0]):storeWkFilter.length+" Wks"}</div>
                  {sorted.map(([dc,s])=>(
                    <div key={dc} style={{marginBottom:14}}>
                      <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                        <span style={{fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{dc}</span>
                        <span style={{fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",fontWeight:600}}>{fmt$(s)}</span>
                      </div>
                      <div style={{height:8,background:"#ede9e3",borderRadius:4,overflow:"hidden"}}>
                        <div style={{width:(s/maxDC*100)+"%",height:"100%",background:DC_COLORS[dc]||"#c8934a",borderRadius:4,transition:"width 0.4s"}}/>
                      </div>
                    </div>
                  ))}
                  <div style={{marginTop:20,borderTop:"1px solid #d8d3c9",paddingTop:16}}>
                    <div style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase",marginBottom:12}}>Top 5 Stores</div>
                    {storeAnalytics.slice(0,5).map((r,i)=>(
                      <div key={r.dc+r.store} style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                        <div>
                          <span style={{fontSize:14,color:"#c8934a",fontFamily:"DM Sans,sans-serif",fontWeight:600}}>{"#"+r.store}</span>
                          <span style={{fontSize:12,color:"#3a5a7a",marginLeft:6}}>{r.dc}</span>
                        </div>
                        <div style={{textAlign:"right"}}>
                          <div style={{fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{fmt$(r.sales)}</div>
                          {r.wd!=null&&<div style={{fontSize:12,color:clr(r.wd),fontFamily:"DM Sans,sans-serif"}}>{fmtD(r.wd)}</div>}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })()}
          </div>

          {/* By Product */}
          <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
            <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{fontSize:13,color:"#2d3752",letterSpacing:0.5,textTransform:"uppercase"}}>
                {(/^\d+$/.test(storeSearch)&&storeSearch?"By Product · Store "+storeSearch:"By Product · "+(storeWkFilter.length===1?FW_LABEL(storeWkFilter[0]):storeWkFilter.length+" Wks")+" · "+(storeDCFilter.length===ALL_DCS.length?"All DCs":storeDCFilter.length+" DCs"))}
              </span>
              <span style={{fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{storeByProduct.length+" products"}</span>
            </div>
            <div style={{overflowX:"auto",maxHeight:480,overflowY:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <THead cols={[{key:"prod",label:"Product"},{key:"sales",label:"This Wk $",num:true},{key:"units",label:"Units",num:true},{key:"aur",label:"AUR",num:true},{key:"lyS",label:"LY $",num:true},{key:"yoyD",label:"YoY $",num:true},{key:"yoyP",label:"YoY %",num:true},{key:"st",label:"ST%",num:true},{key:"spark",label:"Trend FW01→FW12",num:true}]}/>
              <tbody>
                {storeByProduct.map((r,i)=>(
                  <tr key={r.prod} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                    <td style={tdS()}>{r.prod}</td>
                    <td style={tdS("right")}>{fmt$(r.sales)}</td>
                    <td style={tdS("right")}>{fmtU(r.units)}</td>
                    <td style={tdS("right")}>{r.aur!=null?"$"+r.aur.toFixed(2):"—"}</td>
                    <td style={tdS("right","#7a9abc")}>{r.lyS>0?fmt$(r.lyS):"—"}</td>
                    <td style={tdS("right",clr(r.yoyD))}>{r.yoyD!=null?fmtD(r.yoyD):"—"}</td>
                    <td style={tdS("right",clr(r.yoyP))}>{r.yoyP!=null?fmtP(r.yoyP):"—"}</td>
                    <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9"}}><STBar val={r.st}/></td>
                    <td style={{padding:"9px 14px",borderBottom:"1px solid #d8d3c9",textAlign:"right"}}><Sparkline prod={r.prod}/></td>
                  </tr>
                ))}
              </tbody>
            </table>
            </div>
          </div>
        </div>
      )}

      {tab==="district"&&(
        <div>
          {/* Header row */}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20,flexWrap:"wrap",gap:10}}>
            <div style={{fontSize:13,color:"#2d3752"}}>
              {FW_LABEL(selFWSorted[0])}–{FW_LABEL(selFWSorted[selFWSorted.length-1])} · {selFW.length} {selFW.length===1?"week":"weeks"} · FY26 vs FY25
            </div>
            <div style={{display:"flex",gap:8,alignItems:"center"}}>
              <span style={{fontSize:12,color:"#2d3752"}}>SORT:</span>
              {[["s26","FY26 Sales"],["yoyD","YoY $"],["yoyP","YoY %"]].map(([k,l])=>(
                <button key={k} onClick={()=>setDistrictSort(k)} style={{padding:"4px 12px",background:districtSort===k?"#c8934a":"#ffffff",border:"1px solid "+(districtSort===k?"#c8934a":"#d8d3c9"),color:districtSort===k?"#fff":"#5a8aaa",borderRadius:5,cursor:"pointer",fontSize:12,fontFamily:"DM Sans,sans-serif"}}>{l}</button>
              ))}
            </div>
          </div>

          {/* Grand KPIs */}
          {(()=>{
            const allRows = Object.values(districtData).flatMap(r=>r.rows);
            const tot26 = allRows.reduce((a,r)=>a+r.s26,0);
            const tot25 = allRows.reduce((a,r)=>a+r.s25,0);
            const totD = tot26-tot25, totP = tot25>0?totD/tot25*100:null;
            const totStores = new Set(allRows.flatMap(r=>r.stores)).size;
            return (
              <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:20}}>
                <KPI label="FY26 Total Sales" value={fmt$(tot26)}/>
                <KPI label="FY25 Total Sales" value={fmt$(tot25)}/>
                <KPI label="YoY $" value={fmtD(totD)} delta={totD}/>
                <KPI label="YoY %" value={totP!=null?fmtP(totP):"—"} delta={totP}/>
                <KPI label="Districts" value={allRows.length.toString()}/>
              </div>
            );
          })()}

          {/* One card per region */}
          {Object.entries(districtData).sort((a,b)=>a[0].localeCompare(b[0])).map(([region, rData])=>{
            const ryoyD = rData.s26-rData.s25, ryoyP = rData.s25>0?ryoyD/rData.s25*100:null;
            const raur = rData.u26>0?rData.s26/rData.u26:null;
            return (
              <div key={region} style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden",marginBottom:16}}>
                {/* Region header */}
                <div style={{padding:"12px 16px",background:"#ede9e3",borderBottom:"1px solid #d8d3c9",display:"flex",alignItems:"center",gap:16,flexWrap:"wrap"}}>
                  <span style={{fontSize:15,fontWeight:700,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",letterSpacing:0.3,textTransform:"uppercase"}}>{region}</span>
                  <span style={{fontSize:13,color:"#2d3752"}}>{rData.stores+" stores · "+rData.rows.length+" districts"}</span>
                  <div style={{marginLeft:"auto",display:"flex",gap:20}}>
                    <span style={{fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{fmt$(rData.s26)}</span>
                    <span style={{fontSize:14,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{fmt$(rData.s25)}</span>
                    <span style={{fontSize:14,fontWeight:600,color:clr(ryoyD),fontFamily:"DM Sans,sans-serif"}}>{fmtD(ryoyD)}</span>
                    <span style={{fontSize:14,color:clr(ryoyP),fontFamily:"DM Sans,sans-serif"}}>{ryoyP!=null?fmtP(ryoyP):"—"}</span>
                  </div>
                </div>
                {/* District rows */}
                <table style={{width:"100%",borderCollapse:"collapse"}}>
                  <THead cols={[{key:"district",label:"District"},{key:"dm",label:"District Director"},{key:"stores",label:"Stores",num:true},{key:"s26",label:"FY26 Sales",num:true},{key:"u26",label:"FY26 Units",num:true},{key:"aur",label:"AUR",num:true},{key:"s25",label:"FY25 Sales",num:true},{key:"yoyD",label:"YoY $",num:true},{key:"yoyP",label:"YoY %",num:true}]} sort={districtSort} onSort={setDistrictSort}/>
                  <tbody>
                    {rData.rows.map((r,i)=>{
                      const barW = rData.s26>0?r.s26/rData.s26*100:0;
                      const distKey = region+"|||"+r.district;
                      const isExpanded = expandedDistrict===distKey;

                      // Build per-store rows for this district
                      const storeRows = isExpanded ? (()=>{
                        const fw25set = new Set(selFW.map(fw=>FW25_MAP[fw]).filter(Boolean));
                        const storesInDistrict = Object.entries(STORE_META)
                          .filter(([,m])=>m.district===r.district&&selDC.includes(m.dc))
                          .map(([s])=>s);
                        const s26map={}, s25map={};
                        STORE_DATA.filter(d=>selFW.includes(d[0])&&storesInDistrict.includes(String(d[2]))).forEach(d=>{
                          s26map[d[2]]=s26map[d[2]]||{s:0,u:0};
                          s26map[d[2]].s+=d[3]; s26map[d[2]].u+=d[4];
                        });
                        STORE_DATA25.filter(d=>fw25set.has(d[0])&&storesInDistrict.includes(String(d[2]))).forEach(d=>{
                          s25map[d[2]]=s25map[d[2]]||{s:0};
                          s25map[d[2]].s+=d[3];
                        });
                        return storesInDistrict.map(store=>{
                          const c=s26map[store]||{s:0,u:0};
                          const l=s25map[store]||{s:0};
                          const yoyD=c.s-l.s, yoyP=l.s>0?yoyD/l.s*100:null;
                          const aur=c.u>0?c.s/c.u:null;
                          return {store,s26:c.s,u26:c.u,aur,s25:l.s,yoyD,yoyP};
                        }).sort((a,b)=>b.s26-a.s26);
                      })() : [];

                      return (
                        <React.Fragment key={r.district}>
                          <tr
                            onClick={()=>setExpandedDistrict(isExpanded?null:distKey)}
                            style={{background:i%2===0?"#ffffff":"#f5f4f0",cursor:"pointer"}}
                          >
                            <td style={{padding:"10px 14px",borderBottom:"1px solid #d8d3c9"}}>
                              <div style={{display:"flex",alignItems:"center",gap:8}}>
                                <span style={{fontSize:12,color:"#2d3752",width:10}}>{isExpanded?"▼":"▶"}</span>
                                <div>
                                  <div style={{fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{r.district}</div>
                                  <div style={{marginTop:4,height:3,background:"#ede9e3",borderRadius:2,width:"100%"}}>
                                    <div style={{width:barW+"%",height:"100%",background:"#c8934a",borderRadius:2}}/>
                                  </div>
                                </div>
                              </div>
                            </td>
                            <td style={tdS("left","#0a0f1e")}>
                              <div style={{fontSize:13}}>{DISTRICT_MANAGERS[r.district]||"—"}</div>
                              <div style={{fontSize:11,color:"#2d3752",marginTop:1}}>District Director</div>
                            </td>
                            <td style={tdS("right","#5a8aaa")}>{r.stores}</td>
                            <td style={tdS("right")}>{fmt$(r.s26)}</td>
                            <td style={tdS("right")}>{fmtU(r.u26)}</td>
                            <td style={tdS("right")}>{r.aur!=null?"$"+r.aur.toFixed(2):"—"}</td>
                            <td style={tdS("right","#7a9abc")}>{fmt$(r.s25)}</td>
                            <td style={tdS("right",clr(r.yoyD))}>{fmtD(r.yoyD)}</td>
                            <td style={tdS("right",clr(r.yoyP))}>{r.yoyP!=null?fmtP(r.yoyP):"—"}</td>
                          </tr>
                          {isExpanded&&storeRows.map((sr,si)=>{
                            const storeKey = distKey+"|||"+sr.store;
                            const isStoreExpanded = expandedStore===storeKey;
                            // Build product breakdown for this store when expanded
                            const prodRows = isStoreExpanded ? (()=>{
                              const storeMeta = STORE_META[sr.store];
                              if(!storeMeta) return [];
                              const dc = storeMeta.dc;
                              const fw25set = new Set(selFW.map(fw=>FW25_MAP[fw]).filter(Boolean));
                              const prodMap={}, prod25Map={};
                              // FY26: proportion store's sales across products by DC product mix
                              selFW.forEach(fw=>{
                                const storeRow = STORE_DATA.find(d=>d[0]===fw&&d[1]===dc&&String(d[2])===sr.store);
                                if(!storeRow||storeRow[3]===0) return;
                                const dcRows = DATA26.filter(d=>d[0]===fw&&d[1]===dc);
                                const dcTotalUnits = dcRows.reduce((a,d)=>a+d[5],0);
                                if(dcTotalUnits===0) return;
                                dcRows.forEach(d=>{
                                  const share = d[5]/dcTotalUnits;
                                  prodMap[d[2]]=prodMap[d[2]]||{s:0,u:0};
                                  prodMap[d[2]].s+=storeRow[3]*share;
                                  prodMap[d[2]].u+=Math.round(storeRow[4]*share);
                                });
                              });
                              // FY25: same approach with STORE_DATA25 and DATA25
                              fw25set.forEach(fw=>{
                                const storeRow25 = STORE_DATA25.find(d=>d[0]===fw&&d[1]===dc&&String(d[2])===sr.store);
                                if(!storeRow25||storeRow25[3]===0) return;
                                const dcRows25 = DATA25.filter(d=>d[0]===fw&&d[1]===dc);
                                const dcTotalUnits25 = dcRows25.reduce((a,d)=>a+d[4],0);
                                if(dcTotalUnits25===0) return;
                                dcRows25.forEach(d=>{
                                  const share = d[4]/dcTotalUnits25;
                                  prod25Map[d[2]]=prod25Map[d[2]]||{s:0};
                                  prod25Map[d[2]].s+=storeRow25[3]*share;
                                });
                              });
                              return Object.entries(prodMap).map(([prod,c])=>{
                                const l=prod25Map[prod]||{s:0};
                                const yoyD=c.s-l.s, yoyP=l.s>0?yoyD/l.s*100:null;
                                const aur=c.u>0?c.s/c.u:null;
                                return {prod,s26:c.s,u26:c.u,aur,s25:l.s,yoyD,yoyP};
                              }).filter(p=>p.s26>0.5).sort((a,b)=>b.s26-a.s26);
                            })() : [];

                            return (
                              <React.Fragment key={sr.store}>
                                <tr
                                  onClick={()=>{
                                    setExpandedStore(isStoreExpanded?null:storeKey);
                                  }}
                                  style={{background:"#f5f4f0",cursor:"pointer"}}
                                >
                                  <td style={{padding:"7px 14px 7px 38px",borderBottom:"1px solid #d8d3c9"}}>
                                    <div style={{display:"flex",alignItems:"center",gap:6}}>
                                      <span style={{fontSize:11,color:"#2d3752",width:8}}>{isStoreExpanded?"▼":"▶"}</span>
                                      <div>
                                        <div style={{fontSize:14,fontWeight:600,color:"#c8934a",fontFamily:"DM Sans,sans-serif"}}>{"#"+sr.store}</div>
                                        <div style={{fontSize:12,color:"#3a5a7a",marginTop:1}}>{STORE_META[sr.store]?.name||""}</div>
                                      </div>
                                    </div>
                                  </td>
                                  <td style={{...tdS("right","#2d3752"),background:"#f5f4f0"}}>—</td>
                                  <td style={{...tdS("left","#2d3752"),background:"#f5f4f0"}}>—</td>
                                  <td style={{...tdS("right"),background:"#f5f4f0"}}>{fmt$(sr.s26)}</td>
                                  <td style={{...tdS("right"),background:"#f5f4f0"}}>{fmtU(sr.u26)}</td>
                                  <td style={{...tdS("right"),background:"#f5f4f0"}}>{sr.aur!=null?"$"+sr.aur.toFixed(2):"—"}</td>
                                  <td style={{...tdS("right","#2d3752"),background:"#f5f4f0"}}>{sr.s25>0?fmt$(sr.s25):"—"}</td>
                                  <td style={{...tdS("right",clr(sr.yoyD)),background:"#f5f4f0"}}>{sr.s25>0?fmtD(sr.yoyD):"NEW"}</td>
                                  <td style={{...tdS("right",clr(sr.yoyP)),background:"#f5f4f0"}}>{sr.yoyP!=null?fmtP(sr.yoyP):"—"}</td>
                                </tr>
                                {isStoreExpanded&&prodRows.map((pr,pi)=>(
                                  <tr key={pr.prod} style={{background:"#f5f4f0"}}>
                                    <td style={{padding:"6px 14px 6px 62px",borderBottom:"1px solid #d8d3c9",fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{pr.prod}</td>
                                    <td style={{...tdS("left","#2d3752"),background:"#f5f4f0",fontSize:13}}>—</td>
                                    <td style={{...tdS("right","#2a4a6a"),background:"#f5f4f0",fontSize:13}}>—</td>
                                    <td style={{...tdS("right","#a0c4dc"),background:"#f5f4f0",fontSize:13}}>{fmt$(pr.s26)}</td>
                                    <td style={{...tdS("right","#a0c4dc"),background:"#f5f4f0",fontSize:13}}>{fmtU(pr.u26)}</td>
                                    <td style={{...tdS("right","#a0c4dc"),background:"#f5f4f0",fontSize:13}}>{pr.aur!=null?"$"+pr.aur.toFixed(2):"—"}</td>
                                    <td style={{...tdS("right","#5a7a9a"),background:"#f5f4f0",fontSize:13}}>{pr.s25>0?fmt$(pr.s25):"—"}</td>
                                    <td style={{...tdS("right",clr(pr.yoyD)),background:"#f5f4f0",fontSize:13}}>{pr.s25>0?fmtD(pr.yoyD):"NEW"}</td>
                                    <td style={{...tdS("right",clr(pr.yoyP)),background:"#f5f4f0",fontSize:13}}>{pr.yoyP!=null?fmtP(pr.yoyP):"—"}</td>
                                  </tr>
                                ))}
                              </React.Fragment>
                            );
                          })}
                        </React.Fragment>
                      );
                    })}
                    {/* Region subtotal */}
                    <tr style={{background:"#ede9e3",borderTop:"1px solid #d8d3c9"}}>
                      <td style={{padding:"10px 14px",fontSize:13,color:"#c8934a",fontFamily:"DM Sans,sans-serif",fontWeight:700,letterSpacing:0.2}}>{region+" TOTAL"}</td>
                      <td style={tdS("left","#2a4a6a")}>—</td>
                      <td style={tdS("right","#c8934a")}>{rData.stores}</td>
                      <td style={tdS("right","#c8934a")}>{fmt$(rData.s26)}</td>
                      <td style={tdS("right","#c8934a")}>{fmtU(rData.u26)}</td>
                      <td style={tdS("right","#c8934a")}>{raur!=null?"$"+raur.toFixed(2):"—"}</td>
                      <td style={tdS("right","#7a9abc")}>{fmt$(rData.s25)}</td>
                      <td style={tdS("right",clr(ryoyD))}>{fmtD(ryoyD)}</td>
                      <td style={tdS("right",clr(ryoyP))}>{ryoyP!=null?fmtP(ryoyP):"—"}</td>
                    </tr>
                  </tbody>
                </table>
              </div>
            );
          })}
        </div>
      )}

      {tab==="alloc"&&(
        <div>
          {/* Alloc controls — Row 1: Baseline */}
          <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginBottom:isMobile?8:10}}>
            <div style={{fontSize:12,color:"#2d3752",letterSpacing:0.2,minWidth:isMobile?0:60}}>BASELINE:</div>
            {[["last4","Last 4 Wks"],["last8","Last 8 Wks"],["ytd","Full YTD"],["custom","Custom"]].map(([k,l])=>(
              <button key={k} onClick={()=>setAllocBaseline(k)} style={{padding:isMobile?"4px 10px":"5px 14px",background:allocBaseline===k?"#7c3aed":"#ffffff",border:"1px solid "+(allocBaseline===k?"#7c3aed":"#d8d3c9"),color:allocBaseline===k?"#fff":"#5a8aaa",borderRadius:6,cursor:"pointer",fontSize:isMobile?9:10,fontFamily:"DM Sans,sans-serif",whiteSpace:"nowrap"}}>{l}</button>
            ))}
            {allocBaseline==="custom"&&(
              <>
                <div style={{fontSize:12,color:"#2d3752"}}>FROM:</div>
                <select value={allocCustomFrom} onChange={e=>setAllocCustomFrom(Number(e.target.value))} style={{background:"#ede9e3",border:"1px solid #7c3aed",color:"#2d3752",fontSize:12,borderRadius:5,padding:"4px 8px",fontFamily:"DM Sans,sans-serif"}}>
                  {ALL_FWS_FULL.map(fw=><option key={fw} value={fw}>{"FW"+String(fw).slice(-2)}</option>)}
                </select>
                <div style={{fontSize:12,color:"#2d3752"}}>TO:</div>
                <select value={allocCustomTo} onChange={e=>setAllocCustomTo(Number(e.target.value))} style={{background:"#ede9e3",border:"1px solid #7c3aed",color:"#2d3752",fontSize:12,borderRadius:5,padding:"4px 8px",fontFamily:"DM Sans,sans-serif"}}>
                  {ALL_FWS_FULL.filter(fw=>fw>=allocCustomFrom).map(fw=><option key={fw} value={fw}>{"FW"+String(fw).slice(-2)}</option>)}
                </select>
                <div style={{fontSize:12,color:"#7c3aed",fontFamily:"DM Sans,sans-serif"}}>{allocFWs.length+" wks"}</div>
              </>
            )}
          </div>

          {/* Alloc controls — Row 2: Category, DC, Store */}
          <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginBottom:isMobile?8:10}}>
            <div style={{fontSize:12,color:"#2d3752",letterSpacing:0.2}}>CATEGORY:</div>
            <MultiSelect label="Cat" options={ALLOC_CATEGORIES.map(c=>c.key)} selected={allocCategory} onChange={setAllocCategory} fmtOpt={k=>{const c=ALLOC_CATEGORIES.find(x=>x.key===k);return c?c.label:k;}} />
            <div style={{fontSize:12,color:"#2d3752",letterSpacing:0.2,marginLeft:isMobile?0:8}}>DC:</div>
            <MultiSelect label="DC" options={ALL_DCS} selected={allocDC} onChange={setAllocDC}/>
            <div style={{fontSize:12,color:"#2d3752",letterSpacing:0.2,marginLeft:isMobile?0:8}}>STORE:</div>
            <input value={allocSearch} onChange={e=>setAllocSearch(e.target.value)} placeholder="Search store #..." style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:12,borderRadius:5,padding:"4px 8px",fontFamily:"DM Sans,sans-serif",width:isMobile?110:140,outline:"none"}}/>
            {allocSearch&&<button onClick={()=>setAllocSearch("")} style={{background:"transparent",border:"none",color:"#2d3752",cursor:"pointer",fontSize:15,padding:"2px 4px"}}>✕</button>}
          </div>

          {/* Alloc controls — Row 3: Inbound date + Download */}
          <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginBottom:isMobile?12:20}}>
            <div style={{fontSize:12,color:"#2d3752",letterSpacing:0.2}}>INBOUND DATE:</div>
            <input
              type="text"
              value={exportDate}
              onChange={e=>setExportDate(e.target.value)}
              placeholder="YYYYMMDD"
              style={{background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:12,borderRadius:5,padding:"4px 8px",fontFamily:"DM Sans,sans-serif",width:90,outline:"none",textAlign:"center"}}
            />
            <button
              onClick={exportAllocation}
              style={{padding:isMobile?"5px 10px":"6px 14px",background:"linear-gradient(135deg,#4ade80,#22c55e)",border:"none",borderRadius:6,color:"#000",fontSize:isMobile?9:10,fontWeight:700,letterSpacing:0.2,cursor:"pointer",fontFamily:"DM Sans,sans-serif",display:"flex",alignItems:"center",gap:6,whiteSpace:"nowrap"}}
            >
              ⬇ Download Allocation
            </button>
          </div>

          {/* Legend */}
          <div style={{display:"flex",gap:isMobile?8:16,marginBottom:16,flexWrap:"wrap"}}>
            {[["🚩","#6b7280","Insufficient Data"],["🔴","#f87171","Skip (0 cases)"],["🟢","#4ade80","Standard (+1)"],["🟡","#f5a623",isMobile?"Watch (+1)":"Watch (+1, approaching high)"],["🌀","#a3e635",isMobile?"Trending (+2)":"Trending (+2, 2 of 3 wks high)"],["🔵","#60d9fa","High Performer (+2)"]].map(([icon,color,label])=>(
              <div key={label} style={{display:"flex",alignItems:"center",gap:4}}>
                <span style={{fontSize:13}}>{icon}</span>
                <span style={{fontSize:12,color,fontFamily:"DM Sans,sans-serif"}}>{label}</span>
              </div>
            ))}
          </div>

          {/* Main table */}
          <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
            <div style={{padding:"14px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{fontSize:13,color:"#7c3aed",letterSpacing:0.5,textTransform:"uppercase"}}>
                {(()=>{const labels=allocCategory.map(k=>{const c=ALLOC_CATEGORIES.find(x=>x.key===k);return c?c.label:k;});return labels.join(" + ")+" Allocation · "+allocFWs.length+" Wk Baseline";})()}
              </span>
              <span style={{fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{(()=>{if(!allocSearch.trim()) return allocData.length+" stores"; const n=/^\d+$/.test(allocSearch.trim()); return allocData.filter(r=>n?r.store===allocSearch.trim():(STORE_META[r.store]?.name||"").toLowerCase().includes(allocSearch.toLowerCase())).length+" stores";})()}</span>
            </div>
            {/* DC Rec Cases Summary */}
            {(()=>{
              const dcTotals = {};
              const dcSTPct = {};
              allocData.forEach(r=>{ if(!r.insuff && r.recCases!=null) { dcTotals[r.dc]=(dcTotals[r.dc]||0)+r.recCases; } });
              allocData.forEach(r=>{ if(!r.insuff && r.piecesReceived>0) { if(!dcSTPct[r.dc]) dcSTPct[r.dc]={sum:0,n:0}; dcSTPct[r.dc].sum+=r.piecesSold/r.piecesReceived*100; dcSTPct[r.dc].n++; } });
              const entries = allocDC.filter(dc=>dcTotals[dc]!=null).map(dc=>({dc,cases:dcTotals[dc],st:dcSTPct[dc]?dcSTPct[dc].sum/dcSTPct[dc].n:null}));
              if(entries.length===0) return null;
              return (
                <div style={{padding:"10px 16px",borderBottom:"1px solid #d8d3c9",display:"flex",flexWrap:"wrap",gap:8,alignItems:"center"}}>
                  <span style={{fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif",letterSpacing:0.3,textTransform:"uppercase",marginRight:4}}>Rec. Cases by DC:</span>
                  {entries.map(function(entry){var dc=entry.dc; var cases=entry.cases; var st=entry.st; var stColor=st==null?"#5a8aaa":st>=80?"#4ade80":st>=60?"#f5a623":"#f87171"; return (
                    <span key={dc} style={{fontSize:13,fontFamily:"DM Sans,sans-serif",background:"#ede9e3",border:"1px solid #d8d3c9",borderRadius:5,padding:"4px 10px",color:"#c8934a",display:"inline-flex",flexDirection:"column",gap:1}}>
                      <span><span style={{color:"#2d3752"}}>{dc}:</span>{" "}<span style={{color:"#4ade80",fontWeight:700}}>{cases}</span>{" cases"}</span>
                      <span style={{fontSize:12,color:stColor,fontFamily:"DM Sans,sans-serif"}}>{"ST%: "+(st!=null?st.toFixed(0)+"%":"—")}</span>
                    </span>
                  );})}
                  <span style={{marginLeft:"auto",fontSize:13,fontFamily:"DM Sans,sans-serif",color:"#7c3aed",fontWeight:700}}>
                    {"Total: "+entries.reduce((a,e)=>a+e.cases,0)+" cases"}
                  </span>
                </div>
              );
            })()}
            <div style={{overflowX:"auto",maxHeight:isMobile?480:580,overflowY:"auto",WebkitOverflowScrolling:"touch"}}>
            <table style={{width:"100%",borderCollapse:"collapse",minWidth:isMobile?520:800}}>
              <thead>
                <tr style={{background:"#ede9e3"}}>
                  {["Store","DC",...(allocCategory.length>1?["Category"]:[]),"Avg Wkly Sales",...(isMobile?[]:["Pieces Sold","Pieces Rcvd"]),"Store ST%",...(isMobile?[]:["Consec. High Wks","Current Cases"]),"Rec. Cases","Status"].map(h=>(
                    <th key={h} style={{padding:isMobile?"8px 8px":"10px 14px",textAlign:h==="Store"||h==="DC"||h==="Status"?"left":"right",fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif",letterSpacing:0.8,textTransform:"uppercase",borderBottom:"1px solid #d8d3c9",whiteSpace:"nowrap"}}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {(()=>{
                  const rows = [];
                  const dcGroups = {};
                  const isAllocNumeric = /^\d+$/.test(allocSearch.trim());
                  const filteredAlloc = allocSearch.trim()
                    ? allocData.filter(r=> isAllocNumeric ? r.store===allocSearch.trim() : (STORE_META[r.store]?.name||"").toLowerCase().includes(allocSearch.toLowerCase()))
                    : allocData;
                  filteredAlloc.forEach(r=>{ dcGroups[r.dc]=(dcGroups[r.dc]||[]); dcGroups[r.dc].push(r); });
                  let grandTotal = 0;
                  let rowIdx = 0;
                  const subtotalCols = 2+(allocCategory.length>1?1:0)+(isMobile?2:6);

                  Object.entries(dcGroups).forEach(([dc, dcRows])=>{
                    const dcTotal = dcRows.reduce((a,r)=>a+(r.recCases||0),0);
                    grandTotal += dcTotal;

                    dcRows.forEach(r=>{
                      const isInsuff = r.insuff;
                      const statusIcon = isInsuff?"🚩":r.status==="skip"?"🔴":r.status==="high"?"🔵":r.status==="trending"?"🌀":r.status==="watch"?"🟡":"🟢";
                      const statusLabel = isInsuff?"Insufficient Data":r.status==="skip"?"Skip":r.status==="high"?"High Performer":r.status==="trending"?"Trending":r.status==="watch"?"Watch":"Standard";
                      const statusColor = isInsuff?"#6b7280":r.status==="skip"?"#f87171":r.status==="high"?"#60d9fa":r.status==="trending"?"#a3e635":r.status==="watch"?"#f5a623":"#4ade80";
                      const bg = rowIdx%2===0?"#ffffff":"#f5f4f0";
                      const cellP = isMobile?"6px 8px":"9px 14px";
                      rowIdx++;
                      rows.push(
                        <tr key={dc+"-"+r.store+"-"+(r.catKey||"")} style={{background:bg}}>
                          <td style={{padding:cellP,fontSize:isMobile?10:11,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>
                            <div style={{fontWeight:600}}>{"#"+r.store}</div>
                            <div style={{fontSize:11,color:"#3a5a7a",marginTop:2}}>{STORE_META[r.store]?.name||""}</div>
                          </td>
                          <td style={{padding:cellP,fontSize:isMobile?9:10,color:"#2d3752",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9",whiteSpace:"nowrap"}}>{isMobile?dc.replace("DC","").replace("TXDC","TX").replace("CADC","CA").replace("CODC","CO").replace("FLDC","FL").replace("AZDC","AZ"):dc}</td>
                          {allocCategory.length>1&&<td style={{padding:cellP,fontSize:isMobile?9:10,color:"#a78bfa",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{r.catLabel||r.catKey||""}</td>}
                          <td style={{padding:cellP,textAlign:"right",fontSize:isMobile?10:11,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{isInsuff?"—":"$"+r.avgSales.toLocaleString("en-US",{minimumFractionDigits:0,maximumFractionDigits:0})}</td>
                          {!isMobile&&<td style={{padding:cellP,textAlign:"right",borderBottom:"1px solid #d8d3c9"}}>
                            <div style={{fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",fontWeight:600}}>{isInsuff?"—":r.piecesReceived>0?r.piecesSold.toLocaleString():"—"}</div>
                            <div style={{fontSize:11,color:"#2d3752",fontFamily:"DM Sans,sans-serif",marginTop:1}}>est.</div>
                          </td>}
                          {!isMobile&&<td style={{padding:cellP,textAlign:"right",borderBottom:"1px solid #d8d3c9"}}>
                            {isInsuff ? <span style={{color:"#3a5a7a",fontFamily:"DM Sans,sans-serif",fontSize:14}}>—</span> : (
                              <div>
                                <div style={{fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",fontWeight:600}}>{r.piecesReceived>0?r.piecesReceived.toLocaleString():"—"}</div>
                                <div style={{fontSize:11,color:"#2d3752",fontFamily:"DM Sans,sans-serif",marginTop:1}}>{r.casesReceived>0?r.casesReceived+" cases":""}</div>
                              </div>
                            )}
                          </td>}
                          <td style={{padding:cellP,textAlign:"right",borderBottom:"1px solid #d8d3c9"}}>
                            {(()=>{
                              const storeST = (!isInsuff&&r.piecesReceived>0) ? r.piecesSold/r.piecesReceived*100 : null;
                              return storeST!=null
                                ? <div style={{fontSize:isMobile?10:11,color:stClr(storeST),fontFamily:"DM Sans,sans-serif",fontWeight:600}}>{storeST.toFixed(1)+"%"}</div>
                                : <span style={{color:"#3a5a7a",fontFamily:"DM Sans,sans-serif",fontSize:14}}>—</span>;
                            })()}
                          </td>
                          {!isMobile&&<td style={{padding:cellP,textAlign:"right",fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{isInsuff||r.consecHigh===0?"—":r.consecHigh}</td>}
                          {!isMobile&&<td style={{padding:cellP,textAlign:"right",fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{isInsuff?"—":r.currentCases}</td>}
                          <td style={{padding:cellP,textAlign:"right",fontSize:isMobile?12:13,fontWeight:700,color:isInsuff?"#3a5a7a":statusColor,fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{isInsuff?"—":r.recCases}</td>
                          <td style={{padding:cellP,fontSize:isMobile?9:10,color:statusColor,fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9",whiteSpace:"nowrap"}}>{statusIcon+" "+(isMobile?(isInsuff?"Insuff.":r.status==="skip"?"Skip":r.status==="high"?"High":r.status==="trending"?"Trending":r.status==="watch"?"Watch":"Std"):statusLabel)}</td>
                        </tr>
                      );
                    });

                    // DC subtotal row
                    rows.push(
                      <tr key={dc+"-subtotal"} style={{background:"#ede9e3",borderTop:"1px solid #d8d3c9"}}>
                        <td colSpan={subtotalCols} style={{padding:"8px 14px",fontSize:13,color:"#7c3aed",fontFamily:"DM Sans,sans-serif",letterSpacing:0.2,fontWeight:600}}>{dc+" SUBTOTAL · "+dcRows.length+" stores"}</td>
                        <td style={{padding:"8px 14px",textAlign:"right",fontSize:15,fontWeight:700,color:"#7c3aed",fontFamily:"DM Sans,sans-serif"}}>{dcTotal}</td>
                        <td style={{padding:"8px 14px",fontSize:12,color:"#3a5a7a",fontFamily:"DM Sans,sans-serif"}}>{"cases"}</td>
                      </tr>
                    );
                    rowIdx=0;
                  });

                  // Grand total row
                  rows.push(
                    <tr key="grand-total" style={{background:"#ede9e3",borderTop:"2px solid #7c3aed"}}>
                      <td colSpan={subtotalCols} style={{padding:"12px 14px",fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",letterSpacing:0.5,fontWeight:700,textTransform:"uppercase"}}>{"Grand Total · "+allocData.length+" stores"}</td>
                      <td style={{padding:"12px 14px",textAlign:"right",fontSize:17,fontWeight:700,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{grandTotal}</td>
                      <td style={{padding:"12px 14px",fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{"total cases"}</td>
                    </tr>
                  );

                  return rows;
                })()}
              </tbody>
            </table>
            </div>
          </div>

          {/* Info footer */}
          <div style={{marginTop:14,fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif",lineHeight:1.8}}>
            <span style={{marginRight:20}}>SAFETY BUFFER: 15%</span>
            <span style={{marginRight:20}}>STANDARD FLOOR: 60%</span>
            <span style={{marginRight:20}}>HIGH ST THRESHOLD: 85%</span>
            <span style={{marginRight:20}}>CONSEC WEEKS FOR +2: 3</span>
            <span style={{marginRight:20}}>MIN UNITS FOR +2: 15</span>
            <span style={{marginRight:20}}>TREND BONUS: 2 of 3 wks ≥85%</span>
            <span>VOL BOOST: TOP 1/3 STORES ≥78%</span>
          </div>

          {/* Delivery Matrix */}
          <div style={{marginTop:28}}>
            <div style={{fontSize:13,color:"#7c3aed",letterSpacing:0.5,textTransform:"uppercase",marginBottom:12,fontFamily:"DM Sans,sans-serif"}}>
              {allocSearch.trim() ? "Cases Received by Category · Store #"+allocSearch.trim()+" · Fiscal Week" : "Cases Received by Category · Fiscal Week"}
            </div>
            <div style={{overflowX:"auto",border:"1px solid #d8d3c9",borderRadius:10,WebkitOverflowScrolling:"touch"}}>
                <table style={{width:"100%",borderCollapse:"separate",borderSpacing:0,minWidth:700}}>
                  <thead>
                    <tr style={{background:"#ede9e3"}}>
                      <th style={{padding:"10px 14px",textAlign:"left",fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif",letterSpacing:0.3,textTransform:"uppercase",borderBottom:"1px solid #d8d3c9",whiteSpace:"nowrap",minWidth:120,position:"sticky",left:0,background:"#ede9e3",zIndex:2,boxShadow:"2px 0 4px rgba(0,0,0,0.06)"}}>Category</th>
                      {ALL_FWS.map(fw=>(
                        <th key={fw} style={{padding:"10px 10px",textAlign:"center",fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif",letterSpacing:0.2,textTransform:"uppercase",borderBottom:"1px solid #d8d3c9",whiteSpace:"nowrap"}}>{"FW"+String(fw).slice(-2)}</th>
                      ))}
                      <th style={{padding:"10px 14px",textAlign:"right",fontSize:12,color:"#7c3aed",fontFamily:"DM Sans,sans-serif",letterSpacing:0.3,textTransform:"uppercase",borderBottom:"1px solid #d8d3c9"}}>Total</th>
                    </tr>
                  </thead>
                  <tbody>
                    {(()=>{
                      const cats = ["5in Orchid","3in Orchid","2in Orchid","5in Fused","Cascades","Arrangement","Lavender"];
                      const catLabels = {"5in Orchid":"5\" Orchid","3in Orchid":"3\" Orchid","2in Orchid":"2\" Orchid","5in Fused":"5\" Fused","Cascades":"Cascades","Arrangement":"Arrangement","Lavender":"Lavender"};
                      // Map matrix cat label → STORE_OUTBOUND key
                      const catToOutboundKey = {"5in Orchid":"5inch","3in Orchid":"3inch","2in Orchid":null,"5in Fused":"fused","Cascades":"cascades","Arrangement":null,"Lavender":null};
                      const searchedStore = /^\d+$/.test(allocSearch.trim()) ? allocSearch.trim() : null;
                      const rows = [];
                      const totals = {};
                      ALL_FWS.forEach(fw=>{ totals[fw]=0; });
                      let grandTot = 0;

                      let rowIdx = 0;
                      cats.forEach((cat,ci)=>{
                        let rowVals;
                        if(searchedStore) {
                          // Use STORE_OUTBOUND for per-store view
                          const obKey = catToOutboundKey[cat];
                          rowVals = ALL_FWS.map(fw=>{
                            if(!obKey) return 0;
                            const ob = STORE_OUTBOUND[obKey]?.[searchedStore]?.[fw];
                            return ob ? ob[0] : 0; // cases
                          });
                        } else {
                          // Use DELIVERY_MATRIX for DC-level view
                          rowVals = ALL_FWS.map(fw=>{
                            return allocDC.reduce((a,dc)=>{
                              return a + (DELIVERY_MATRIX[dc]?.[cat]?.[String(fw)]||0);
                            },0);
                          });
                        }
                        const rowTotal = rowVals.reduce((a,v)=>a+v,0);
                        if(rowTotal===0) return;
                        grandTot += rowTotal;
                        rowVals.forEach((v,i)=>{ totals[ALL_FWS[i]]+=v; });
                        const maxVal = Math.max(...rowVals,1);
                        const rowBg = rowIdx%2===0?"#ffffff":"#f5f4f0";
                        rowIdx++;

                        rows.push(
                          <tr key={cat} style={{background:rowBg}}>
                            <td style={{padding:"9px 14px",fontSize:14,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9",whiteSpace:"nowrap",position:"sticky",left:0,background:rowBg,zIndex:1,boxShadow:"2px 0 4px rgba(0,0,0,0.06)"}}>{catLabels[cat]}</td>
                            {rowVals.map((v,i)=>{
                              const intensity = v>0 ? Math.max(0.15, v/maxVal) : 0;
                              return (
                                <td key={i} style={{padding:"9px 10px",textAlign:"center",borderBottom:"1px solid #d8d3c9",position:"relative"}}>
                                  {v>0 && <div style={{position:"absolute",inset:0,background:"#7c3aed",opacity:intensity*0.25,borderRadius:2}}/>}
                                  <span style={{position:"relative",fontSize:14,color:v>0?"#0a0f1e":"#2d3752",fontFamily:"DM Sans,sans-serif",fontWeight:v>0?600:400}}>{v>0?v:"—"}</span>
                                </td>
                              );
                            })}
                            <td style={{padding:"9px 14px",textAlign:"right",fontSize:14,fontWeight:700,color:"#7c3aed",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{rowTotal}</td>
                          </tr>
                        );
                      });

                      // Total row
                      rows.push(
                        <tr key="total" style={{background:"#ede9e3",borderTop:"1px solid #d8d3c9"}}>
                          <td style={{padding:"10px 14px",fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",fontWeight:700,letterSpacing:0.2,position:"sticky",left:0,background:"#ede9e3",zIndex:1,boxShadow:"2px 0 4px rgba(0,0,0,0.06)"}}>TOTAL</td>
                          {ALL_FWS.map(fw=>(
                            <td key={fw} style={{padding:"10px 10px",textAlign:"center",fontSize:14,fontWeight:700,color:totals[fw]>0?"#0a0f1e":"#2d3752",fontFamily:"DM Sans,sans-serif"}}>{totals[fw]>0?totals[fw]:"—"}</td>
                          ))}
                          <td style={{padding:"10px 14px",textAlign:"right",fontSize:15,fontWeight:700,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{grandTot}</td>
                        </tr>
                      );
                      return rows;
                    })()}
                  </tbody>
                </table>
            </div>
          </div>

          {/* Corrections Log */}
          {(()=>{
            // Map allocCategory key → product names in corrections log
            const catProdMap = {
              "5inch":    ["PLANT-5-ORCHID","PLANT-ORCHID","ORCHID-PREMIUM-CERAMIC","ORCHID-PLANT","ORCHID-COLOR-EVERYDAY-5 IN","ORCHID-LARGE WHITE"],
              "3inch":    ["PLANT-ORCHID-SMALL","ORCHID-SMALL","ORCHID-TEACUP-3\""],
              "fused":    ["PLANT-ORCHID-FUSED","ORCHID-FUSED-COLORED","ORCHID-CASCADE-FUSED"],
              "cascades": ["PLANT-ORCHID-CASCADE-PREMIUM","ORCHID-CASCADE","ORCHID-WATERFALL-PREMIUM-5IN","PLANT-ORCHID-PREMIUM CASCADE"],
            };
            const catProds = allocCategory.flatMap(k=>catProdMap[k]||[]);
            const filteredLog = CORRECTIONS_LOG.filter(r=>{
              if(!allocDC.includes(r.dc)) return false;
              if(catProds.length>0 && !catProds.includes(r.product)) return false;
              if(allocSearch.trim()){
                const isNum = /^\d+$/.test(allocSearch.trim());
                if(isNum && r.store!==allocSearch.trim()) return false;
                if(!isNum && !(STORE_META[r.store]?.name||"").toLowerCase().includes(allocSearch.toLowerCase())) return false;
              }
              return true;
            });
            if(filteredLog.length===0) return null;
            return (
            <div style={{marginTop:28}}>
              <div style={{fontSize:13,color:"#f5a623",letterSpacing:0.5,textTransform:"uppercase",marginBottom:4,fontFamily:"DM Sans,sans-serif",display:"flex",alignItems:"center",gap:8}}>
                <span>⚠</span>
                <span>Corrections Log — Outbound Data Overrides</span>
                <span style={{fontSize:12,color:"#3a5a7a",marginLeft:4}}>Source: DC Template Orders Del Wk 12 / 13 / 14 / 15</span>
              </div>
              <div style={{fontSize:12,color:"#3a5a7a",fontFamily:"DM Sans,sans-serif",marginBottom:12}}>
                The following store outbound quantities were corrected based on the DC Template file. Original FY2026 export values differed from actual cases shipped. (FW15: 0 corrections — template matched export exactly.)
              </div>
              <div style={{background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:10,overflow:"hidden"}}>
                <div style={{overflowX:"auto",maxHeight:320,overflowY:"auto"}}>
                  <table style={{width:"100%",borderCollapse:"collapse"}}>
                    <thead>
                      <tr style={{background:"#f5f4f0"}}>
                        {["FW","DC","Store","Product","Original Cases","Corrected Cases","Difference"].map(h=>(
                          <th key={h} style={{padding:"8px 12px",textAlign:h==="Difference"||h==="Original Cases"||h==="Corrected Cases"?"right":"left",fontSize:12,color:"#7a5a00",fontFamily:"DM Sans,sans-serif",letterSpacing:0.2,textTransform:"uppercase",borderBottom:"1px solid #2a1a00",whiteSpace:"nowrap"}}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {filteredLog.map((r,i)=>(
                        <tr key={i} style={{background:i%2===0?"#ffffff":"#f5f4f0"}}>
                          <td style={{padding:"7px 12px",fontSize:13,color:"#a07030",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{"FW"+String(r.fw).slice(-2)}</td>
                          <td style={{padding:"7px 12px",fontSize:13,color:"#7a5a00",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{r.dc}</td>
                          <td style={{padding:"7px 12px",fontSize:13,borderBottom:"1px solid #d8d3c9"}}>
                            <div style={{fontWeight:600,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{"#"+r.store}</div>
                            <div style={{fontSize:11,color:"#3a5a7a",marginTop:1}}>{STORE_META[r.store]?.name||""}</div>
                          </td>
                          <td style={{padding:"7px 12px",fontSize:13,color:"#a07030",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{r.product}</td>
                          <td style={{padding:"7px 12px",textAlign:"right",fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9",textDecoration:"line-through"}}>{r.orig}</td>
                          <td style={{padding:"7px 12px",textAlign:"right",fontSize:13,fontWeight:600,color:"#4ade80",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{r.corrected}</td>
                          <td style={{padding:"7px 12px",textAlign:"right",fontSize:13,color:r.diff<0?"#f87171":"#4ade80",fontFamily:"DM Sans,sans-serif",borderBottom:"1px solid #d8d3c9"}}>{r.diff>0?"+"+r.diff:r.diff}</td>
                        </tr>
                      ))}
                    </tbody>
                    <tfoot>
                      <tr style={{background:"#f5f4f0",borderTop:"1px solid #d8d3c9"}}>
                        <td colSpan={4} style={{padding:"8px 12px",fontSize:13,color:"#f5a623",fontFamily:"DM Sans,sans-serif",fontWeight:700}}>
                          {filteredLog.length+" corrections · "+[...new Set(filteredLog.map(r=>r.dc))].length+" DCs · "+[...new Set(filteredLog.map(r=>r.store))].length+" stores"}
                        </td>
                        <td style={{padding:"8px 12px",textAlign:"right",fontSize:13,color:"#2d3752",fontFamily:"DM Sans,sans-serif",fontWeight:700,textDecoration:"line-through"}}>{filteredLog.reduce((a,r)=>a+r.orig,0)}</td>
                        <td style={{padding:"8px 12px",textAlign:"right",fontSize:13,color:"#4ade80",fontFamily:"DM Sans,sans-serif",fontWeight:700}}>{filteredLog.reduce((a,r)=>a+r.corrected,0)}</td>
                        <td style={{padding:"8px 12px",textAlign:"right",fontSize:13,color:"#f87171",fontFamily:"DM Sans,sans-serif",fontWeight:700}}>{filteredLog.reduce((a,r)=>a+r.diff,0)}</td>
                      </tr>
                    </tfoot>
                  </table>
                </div>
              </div>
            </div>
            );
          })()}
        </div>
      )}
      </div>

      {/* Floating Insights Button */}
      <button onClick={()=>setInsightsOpen(o=>!o)} style={{position:"fixed",bottom:isMobile?16:28,right:isMobile?16:28,zIndex:1000,background:"linear-gradient(135deg,#c8934a,#7c3aed)",border:"none",borderRadius:50,width:isMobile?48:56,height:isMobile?48:56,cursor:"pointer",boxShadow:"0 4px 20px rgba(124,58,237,0.5)",display:isMobile&&insightsOpen?"none":"flex",alignItems:"center",justifyContent:"center",fontSize:isMobile?18:22,transition:"all 0.2s"}}>
        {insightsOpen?"✕":"💡"}
      </button>

      {/* Floating Insights Panel */}
      {insightsOpen&&(
        <div style={{position:"fixed",bottom:isMobile?0:96,right:isMobile?0:28,zIndex:999,width:isMobile?"100%":520,height:isMobile?"90vh":undefined,maxHeight:isMobile?"90vh":"75vh",background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:isMobile?"14px 14px 0 0":14,boxShadow:"0 8px 40px rgba(0,0,0,0.6)",display:"flex",flexDirection:"column",overflow:"hidden"}}>
          {/* Panel Header */}
          <div style={{padding:isMobile?"12px 16px":"14px 18px",background:"#ffffff",borderBottom:"1px solid #d8d3c9",display:"flex",alignItems:"center",gap:10,flexShrink:0}}>
            <span style={{fontSize:14}}>💡</span>
            <span style={{fontSize:14,fontWeight:700,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif",letterSpacing:0.3}}>INSIGHTS</span>
            <div style={{marginLeft:"auto",display:"flex",gap:6,alignItems:"center"}}>
              {[["chat","Ask"],["cards","Quick Insights"]].map(([k,l])=>(
                <button key={k} onClick={()=>setInsightsTab(k)} style={{padding:isMobile?"8px 18px":"7px 16px",background:insightsTab===k?"#c8934a":"transparent",border:"1px solid "+(insightsTab===k?"#c8934a":"#d8d3c9"),color:insightsTab===k?"#fff":"#2d3752",borderRadius:5,cursor:"pointer",fontSize:isMobile?13:12,fontFamily:"DM Sans,sans-serif",letterSpacing:0.2}}>{l}</button>
              ))}
              {isMobile&&(
                <button onClick={()=>setInsightsOpen(false)} style={{marginLeft:6,background:"#e4ddd4",border:"none",borderRadius:20,width:32,height:32,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:"#0a0f1e",fontSize:17,flexShrink:0}}>✕</button>
              )}
            </div>
          </div>

          {/* Quick Insights Cards */}
          {insightsTab==="cards"&&(
            <div style={{overflowY:"auto",padding:isMobile?12:16,display:"flex",flexDirection:"column",gap:12,flex:1,WebkitOverflowScrolling:"touch"}}>
              {(()=>{
                const {storeSTList,highPerf,zeroPieces,worstDist,dcSTRanked} = insightsData;
                const Card = ({icon,title,children})=>(
                  <div style={{background:"#f5f4f0",border:"1px solid #d8d3c9",borderRadius:8,padding:"12px 14px"}}>
                    <div style={{fontSize:12,color:"#2d3752",fontFamily:"DM Sans,sans-serif",letterSpacing:0.3,textTransform:"uppercase",marginBottom:8,display:"flex",alignItems:"center",gap:6}}>
                      <span style={{fontSize:15}}>{icon}</span>{title}
                    </div>
                    {children}
                  </div>
                );
                return (
                  <>
                    <Card icon="🏆" title={"Top 5 Stores — Store ST% (5\" Orchids, Last 4 Wks)"}>
                      {storeSTList.slice(0,5).map(r=>(
                        <div key={r.store} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderBottom:"1px solid #d8d3c9"}}>
                          <span style={{fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{"#"+r.store+" "+r.name.split("-").slice(0,2).join("-")}</span>
                          <span style={{fontSize:13,fontWeight:700,color:"#4ade80",fontFamily:"DM Sans,sans-serif"}}>{r.st.toFixed(1)+"%"}</span>
                        </div>
                      ))}
                    </Card>
                    <Card icon="⚠️" title={"Bottom 5 Stores — Store ST% (5\" Orchids, Last 4 Wks)"}>
                      {[...storeSTList].reverse().slice(0,5).map(r=>(
                        <div key={r.store} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderBottom:"1px solid #d8d3c9"}}>
                          <span style={{fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{"#"+r.store+" "+r.name.split("-").slice(0,2).join("-")}</span>
                          <span style={{fontSize:13,fontWeight:700,color:"#f87171",fontFamily:"DM Sans,sans-serif"}}>{r.st.toFixed(1)+"%"}</span>
                        </div>
                      ))}
                    </Card>
                    <Card icon="🔵" title={"High Performers (+2 eligible) — "+highPerf.length+" stores"}>
                      {highPerf.length===0
                        ? <div style={{fontSize:13,color:"#3a5a7a",fontFamily:"DM Sans,sans-serif"}}>No stores qualify yet</div>
                        : highPerf.slice(0,6).map(r=>(
                          <div key={r.store} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderBottom:"1px solid #d8d3c9"}}>
                            <span style={{fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{"#"+r.store+" "+r.name.split("-").slice(0,2).join("-")}</span>
                            <span style={{fontSize:13,color:"#60d9fa",fontFamily:"DM Sans,sans-serif"}}>{r.consec+" consec wks"}</span>
                          </div>
                        ))
                      }
                    </Card>
                    <Card icon="📦" title={"0 Pieces Rcvd (5\" Orchids, Last 4 Wks) — "+zeroPieces.length+" stores"}>
                      {zeroPieces.slice(0,5).map(s=>(
                        <div key={s} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderBottom:"1px solid #d8d3c9"}}>
                          <span style={{fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{"#"+s}</span>
                          <span style={{fontSize:12,color:"#3a5a7a",fontFamily:"DM Sans,sans-serif"}}>{(STORE_META[s]?.name||"").split("-").slice(0,2).join("-")}</span>
                        </div>
                      ))}
                      {zeroPieces.length>5&&<div style={{fontSize:12,color:"#3a5a7a",fontFamily:"DM Sans,sans-serif",marginTop:4}}>+{zeroPieces.length-5} more</div>}
                    </Card>
                    <Card icon="📉" title="Worst 5 Districts — YoY % (YTD)">
                      {worstDist.map(r=>(
                        <div key={r.district} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderBottom:"1px solid #d8d3c9"}}>
                          <span style={{fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{r.district}</span>
                          <span style={{fontSize:13,fontWeight:700,color:"#f87171",fontFamily:"DM Sans,sans-serif"}}>{r.yoyP.toFixed(1)+"%"}</span>
                        </div>
                      ))}
                    </Card>
                    <Card icon="✅" title={"DC Avg ST% Ranking (5\" Orchids, Last 4 Wks)"}>
                      {dcSTRanked.map(r=>(
                        <div key={r.dc} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderBottom:"1px solid #d8d3c9"}}>
                          <span style={{fontSize:13,color:"#0a0f1e",fontFamily:"DM Sans,sans-serif"}}>{r.dc}</span>
                          <span style={{fontSize:13,fontWeight:700,color:r.avg>=80?"#4ade80":r.avg>=60?"#f5a623":"#f87171",fontFamily:"DM Sans,sans-serif"}}>{r.avg.toFixed(1)+"%"}</span>
                        </div>
                      ))}
                    </Card>
                    <Card icon="🔧" title={"Corrections Summary — "+CORRECTIONS_LOG.length+" overrides"}>
                      {[...new Set(CORRECTIONS_LOG.map(r=>r.dc))].map(dc=>{
                        const rows=CORRECTIONS_LOG.filter(r=>r.dc===dc);
                        const diff=rows.reduce((a,r)=>a+r.diff,0);
                        return (
                          <div key={dc} style={{padding:"3px 0",borderBottom:"1px solid #d8d3c9"}}>
                            <div style={{display:"flex",justifyContent:"space-between"}}>
                              <span style={{fontSize:13,color:"#a07030",fontFamily:"DM Sans,sans-serif"}}>{dc}</span>
                              <span style={{fontSize:13,color:"#f87171",fontFamily:"DM Sans,sans-serif"}}>{diff+" cases"}</span>
                            </div>
                            <div style={{fontSize:12,color:"#3a5a7a",fontFamily:"DM Sans,sans-serif"}}>{rows.length+" stores · FW"+String(CORRECTIONS_LOG[0]?.fw||0).slice(-2)}</div>
                          </div>
                        );
                      })}
                    </Card>
                  </>
                );
              })()}
            </div>
          )}

          {/* AI Chat */}
          {insightsTab==="chat"&&(
            <div style={{display:"flex",flexDirection:"column",flex:1,overflow:"hidden"}}>
              <div style={{flex:1,overflowY:"auto",padding:isMobile?12:16,display:"flex",flexDirection:"column",gap:10,WebkitOverflowScrolling:"touch"}}>
                {chatMessages.length===0&&(
                  <div style={{color:"#2d3752",fontSize:isMobile?13:12,fontFamily:"DM Sans,sans-serif",lineHeight:1.8}}>
                    <div style={{marginBottom:8,color:"#2d3752"}}>Ask me anything about the dashboard data. Examples:</div>
                    {["Which stores in FULRTNCADC should get +2 cases?","What happened to 5\" Fused sales in FW07?","Which district had the best YoY performance?","Compare Central vs SoCal YTD","Which stores have 0 pieces received this month?"].map(q=>(
                      <div key={q} onClick={()=>setChatInput(q)} style={{cursor:"pointer",padding:isMobile?"8px 10px":"6px 10px",borderRadius:4,border:"1px solid #d8d3c9",marginBottom:6,color:"#c8934a",fontSize:isMobile?13:12,lineHeight:1.5}}>{q}</div>
                    ))}
                  </div>
                )}
                {chatMessages.map((m,i)=>(
                  <div key={i} style={{display:"flex",justifyContent:m.role==="user"?"flex-end":"flex-start"}}>
                    <div style={{maxWidth:"85%",padding:isMobile?"10px 14px":"10px 14px",borderRadius:8,background:m.role==="user"?"#c8934a":"#ede9e3",border:"1px solid "+(m.role==="user"?"#c8934a":"#d81e30"),fontSize:isMobile?14:13,color:m.role==="user"?"#fff":"#0a0f1e",fontFamily:"DM Sans,sans-serif",lineHeight:1.7,whiteSpace:"pre-wrap"}}>{m.role==="assistant" ? React.createElement("span", {dangerouslySetInnerHTML:{__html:m.content.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>").replace(/\n/g,"<br/>").replace(/^- /gm,"\u2022 ")}}) : m.content}</div>
                  </div>
                ))}
                {chatLoading&&(
                  <div style={{display:"flex",justifyContent:"flex-start"}}>
                    <div style={{padding:"8px 12px",borderRadius:8,background:"#ede9e3",border:"1px solid #d8d3c9",fontSize:14,color:"#2d3752",fontFamily:"DM Sans,sans-serif"}}>Thinking...</div>
                  </div>
                )}
              </div>
              <div style={{padding:isMobile?"12px 16px 20px":"12px 16px",borderTop:"1px solid #d8d3c9",display:"flex",gap:8,flexShrink:0}}>
                <input
                  value={chatInput}
                  onChange={e=>setChatInput(e.target.value)}
                  onKeyDown={async e=>{
                    if(e.key==="Enter"&&!e.shiftKey&&chatInput.trim()&&!chatLoading){
                      e.preventDefault();
                      await handleChatSend(chatInput.trim());
                    }
                  }}
                  placeholder="Ask about your data..."
                  style={{flex:1,background:"#ede9e3",border:"1px solid #d8d3c9",color:"#2d3752",fontSize:isMobile?14:13,borderRadius:6,padding:isMobile?"12px 14px":"10px 14px",fontFamily:"DM Sans,sans-serif",outline:"none"}}
                />
                <button onClick={()=>handleChatSend(chatInput.trim())} style={{padding:isMobile?"12px 20px":"10px 16px",background:"#c8934a",border:"none",borderRadius:6,color:"#fff",cursor:"pointer",fontSize:isMobile?16:14,fontFamily:"DM Sans,sans-serif",flexShrink:0}}>↵</button>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );

  // ── PASSWORD GATE WRAPPER ─────────────────────────────────────────────────
  const handleLogin = () => {
    if(pwInput === CORRECT_PASSWORD){
      setAuthenticated(true);
    } else {
      setPwError(true);
      setPwShake(true);
      setPwInput("");
      setTimeout(()=>setPwShake(false), 600);
    }
  };

  if(!authenticated) return (
    <div style={{minHeight:"100vh",background:"#edeae3",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'DM Sans',sans-serif"}}>
      <style>{`@keyframes shake{0%,100%{transform:translateX(0)}20%,60%{transform:translateX(-8px)}40%,80%{transform:translateX(8px)}}`}</style>
      <div style={{width:380,background:"#ffffff",border:"1px solid #d8d3c9",borderRadius:16,padding:"40px 36px",boxShadow:"0 20px 60px rgba(0,0,0,0.6)",textAlign:"center",animation:pwShake?"shake 0.5s ease":"none"}}>
        {LOGO_B64&&<img src={LOGO_B64} alt="Sprouts" style={{height:48,marginBottom:24,objectFit:"contain"}}/>}
        <div style={{fontSize:15,fontWeight:700,color:"#0a0f1e",letterSpacing:0.5,textTransform:"uppercase",marginBottom:6}}>Floral Sales Dashboard</div>
        <div style={{fontSize:13,color:"#2d3752",marginBottom:32,letterSpacing:0.2}}>Internal Use Only</div>
        <input
          type="password"
          value={pwInput}
          onChange={e=>{setPwInput(e.target.value);setPwError(false);}}
          onKeyDown={e=>e.key==="Enter"&&handleLogin()}
          placeholder="Enter password"
          autoFocus
          style={{width:"100%",boxSizing:"border-box",background:"#ede9e3",border:"1px solid "+(pwError?"#f87171":"#d8d3c9"),color:"#0a0f1e",fontSize:15,padding:"12px 16px",borderRadius:8,outline:"none",marginBottom:12,fontFamily:"'DM Sans',sans-serif",letterSpacing:0.2,textAlign:"center"}}
        />
        {pwError&&<div style={{fontSize:13,color:"#f87171",marginBottom:12,letterSpacing:0.2}}>Incorrect password. Please try again.</div>}
        <button onClick={handleLogin} style={{width:"100%",padding:"12px",background:"#c8934a",border:"none",borderRadius:8,color:"#fff",fontSize:14,fontWeight:700,letterSpacing:0.5,textTransform:"uppercase",cursor:"pointer"}}>
          Access Dashboard
        </button>
        <div style={{fontSize:12,color:"#2d3752",marginTop:24,letterSpacing:0.2}}>© Boring Deco · Sprouts Farmers Market</div>
      </div>
    </div>
  );

  return dashboard;
}
